#[then("both suggest-next outputs should be identical")]
async fn then_identical_suggest_next_outputs(world: &mut World) {
    let first = world
        .xtask_context()
        .env
        .get("IDEMPOTENCY_FIRST_OUTPUT")
        .expect("First output not captured");
    let second = world
        .xtask_context()
        .env
        .get("IDEMPOTENCY_SECOND_OUTPUT")
        .expect("Second output not captured");

    // Normalize whitespace and filter out timing and non-deterministic cargo messages
    let normalize = |s: &str| -> String {
        s.lines()
            .map(|line| {
                // Strip cargo timing like "in 0.14s" to make output deterministic
                let re = regex::Regex::new(r"\bin \d+\.\d+s\b").unwrap();
                re.replace_all(line.trim(), "in X.XXs").to_string()
            })
            .filter(|line| {
                // Filter out non-deterministic cargo messages
                !line.is_empty() && !line.contains("Blocking waiting for file lock")
            })
            .collect::<Vec<_>>()
            .join("\n")
    };

    let first_normalized = normalize(first);
    let second_normalized = normalize(second);

    assert_eq!(first_normalized, second_normalized, "suggest-next outputs should be identical");
}

