use business_core::ports::TaskRepository;
use business_core::use_cases;
use model::{Task as ModelTask, TaskStatus};
use prost_types::Timestamp;
use task::v1::{
    CreateTaskRequest, CreateTaskResponse, GetTaskRequest, GetTaskResponse, ListTasksRequest,
    ListTasksResponse, Task as ProtoTask, UpdateStatusRequest, UpdateStatusResponse,
    task_service_server::{TaskService, TaskServiceServer},
};

pub struct TaskServiceImpl {
    repo: Arc<dyn TaskRepository>,
}

impl TaskServiceImpl {
    /// Create a new TaskServiceImpl with the given repository (useful for testing)
    pub fn new(repo: Arc<dyn TaskRepository>) -> Self {
        Self { repo }
    }
}

#[tonic::async_trait]
impl TaskService for TaskServiceImpl {
    async fn create_task(
        &self,
        request: Request<CreateTaskRequest>,
    ) -> Result<Response<CreateTaskResponse>, Status> {
        let title = request.into_inner().title;
        let task = use_cases::create_task(&*self.repo, title).await.map_err(Status::internal)?;
        let proto_task = model_task_to_proto(&task);
        Ok(Response::new(CreateTaskResponse { task: Some(proto_task) }))
    }

    async fn get_task(
        &self,
        request: Request<GetTaskRequest>,
    ) -> Result<Response<GetTaskResponse>, Status> {
        let id = request.into_inner().id;
        let task = use_cases::get_task(&*self.repo, id).await.map_err(Status::internal)?;
        let proto_task =
            task.map(|t| model_task_to_proto(&t)).ok_or(Status::not_found("task not found"))?;
        Ok(Response::new(GetTaskResponse { task: Some(proto_task) }))
    }

    async fn list_tasks(
        &self,
        _request: Request<ListTasksRequest>,
    ) -> Result<Response<ListTasksResponse>, Status> {
        let tasks = use_cases::list_tasks(&*self.repo).await.map_err(Status::internal)?;
        let proto_tasks = tasks.into_iter().map(|t| model_task_to_proto(&t)).collect();
        Ok(Response::new(ListTasksResponse { tasks: proto_tasks }))
    }

    async fn update_status(
        &self,
        request: Request<UpdateStatusRequest>,
    ) -> Result<Response<UpdateStatusResponse>, Status> {
        let inner = request.into_inner();
        let id = inner.id;
        let status = parse_task_status(&inner.status)?;
        let task = use_cases::update_task_status(&*self.repo, id, status)
            .await
            .map_err(Status::internal)?;
        let proto_task =
            task.map(|t| model_task_to_proto(&t)).ok_or(Status::not_found("task not found"))?;
        Ok(Response::new(UpdateStatusResponse { task: Some(proto_task) }))
    }
}

fn model_task_to_proto(task: &ModelTask) -> ProtoTask {
    ProtoTask {
        id: task.id.clone(),
        title: task.title.clone(),
        status: format!("{:?}", task.status),
        created_at: Some(Timestamp {
            seconds: task.created_at.timestamp(),
            nanos: task.created_at.timestamp_subsec_nanos() as i32,
        }),
    }
}

fn parse_task_status(s: &str) -> Result<TaskStatus, Status> {
    match s {
        "Pending" => Ok(TaskStatus::Pending),
        "InProgress" => Ok(TaskStatus::InProgress),
        "Completed" => Ok(TaskStatus::Completed),
        _ => Err(Status::invalid_argument(format!("Invalid task status: {}", s))),
    }
}

pub async fn spawn(
    port: u16,
    repo: Arc<dyn TaskRepository>,
) -> Result<(), Box<dyn std::error::Error + Send + Sync>> {
    let addr = format!("[::1]:{}", port).parse()?;
    let service = TaskServiceImpl { repo };

    Server::builder().add_service(TaskServiceServer::new(service)).serve(addr).await?;

    Ok(())
}

use adapters_grpc::spawn;
use adapters_grpc::task::v1::task_service_client::TaskServiceClient;
use adapters_grpc::task::v1::{CreateTaskRequest, GetTaskRequest, ListTasksRequest};
use async_trait::async_trait;
use business_core::ports::TaskRepository;
use model::{Task, TaskStatus};
use std::collections::HashMap;
use std::sync::{Arc, Mutex};

/// In-memory task repository for testing
struct InMemoryTaskRepository {
    tasks: Mutex<HashMap<String, Task>>,
}

impl InMemoryTaskRepository {
    fn new() -> Self {
        Self { tasks: Mutex::new(HashMap::new()) }
    }
}

#[async_trait]
impl TaskRepository for InMemoryTaskRepository {
    async fn save(&self, task: &Task) -> Result<(), String> {
        let mut tasks = self.tasks.lock().unwrap();
        tasks.insert(task.id.clone(), task.clone());
        Ok(())
    }

    async fn find_by_id(&self, id: &str) -> Result<Option<Task>, String> {
        let tasks = self.tasks.lock().unwrap();
        Ok(tasks.get(id).cloned())
    }

    async fn find_all(&self) -> Result<Vec<Task>, String> {
        let tasks = self.tasks.lock().unwrap();
        Ok(tasks.values().cloned().collect())
    }

    async fn update_status(&self, id: &str, status: TaskStatus) -> Result<Option<Task>, String> {
        let mut tasks = self.tasks.lock().unwrap();
        if let Some(task) = tasks.get_mut(id) {
            task.status = status;
            Ok(Some(task.clone()))
        } else {
            Ok(None)
        }
    }
}

/// gRPC adapter smoke test
///
/// This test verifies the gRPC service works end-to-end with an in-memory repository.
/// It's marked with #[ignore] by default to keep CI fast.
///
/// Run with: cargo test -p adapters-grpc --test smoke -- --ignored
#[tokio::test]
#[ignore = "gRPC smoke test; run with cargo test -- --ignored"]
async fn test_grpc_service_create_task() {
    // Create in-memory repository
    let repo: Arc<dyn TaskRepository> = Arc::new(InMemoryTaskRepository::new());

    // Start gRPC server on random port
    // Start gRPC server on random port
    let listener = std::net::TcpListener::bind("127.0.0.1:0").unwrap();
    let port = listener.local_addr().unwrap().port();
    drop(listener); // Release port so server can bind to it
    let server_repo = repo.clone();

    // Spawn server in background task
    let server_handle = tokio::spawn(async move { spawn(port, server_repo).await });

    // Give server time to start
    tokio::time::sleep(tokio::time::Duration::from_millis(500)).await;

    // Create gRPC client
    let addr = format!("http://[::1]:{}", port);
    let mut client =
        TaskServiceClient::connect(addr).await.expect("Failed to connect to gRPC server");

    // Test 1: Create a task
    let create_request = CreateTaskRequest { title: "gRPC smoke test task".to_string() };

    let create_response =
        client.create_task(create_request).await.expect("Failed to create task").into_inner();

    let created_task = create_response.task.expect("No task in create response");
    assert_eq!(created_task.title, "gRPC smoke test task");
    assert_eq!(created_task.status, "Pending");

    let task_id = created_task.id.clone();

    // Test 2: Get the task
    let get_request = GetTaskRequest { id: task_id.clone() };

    let get_response = client.get_task(get_request).await.expect("Failed to get task").into_inner();
    let fetched_task = get_response.task.expect("No task in get response");

    assert_eq!(fetched_task.id, task_id);
    assert_eq!(fetched_task.title, "gRPC smoke test task");

    // Test 3: List tasks
    let list_request = ListTasksRequest {};

    let list_response =
        client.list_tasks(list_request).await.expect("Failed to list tasks").into_inner();

    assert_eq!(list_response.tasks.len(), 1);
    assert_eq!(list_response.tasks[0].id, task_id);

    // Cleanup: abort server
    server_handle.abort();

    println!("✓ gRPC adapter smoke test passed");
}

//! Filesystem-backed governance repository for task state.
//!
//! This crate provides an implementation of `GovernanceRepository` that
//! reads static task definitions from the spec tree and persists task
//! status to a separate `tasks_state.yaml` file on disk.
//!
//! It is deliberately simple and transparent:
//! - `tasks_def` exposes read-only access to the canonical task definitions
//!   derived from `specs/tasks.yaml`.
//! - `tasks_state` persists `TaskStatus` updates without rewriting the spec.
//!
//! This is the "write layer" for the Rust-as-Spec platform cell: the kernel
//! can enforce governance rules while leaving the fork's task YAML under
//! human control.

/// Helpers for loading canonical task definitions from the spec tree.
///
/// This module treats `specs/tasks.yaml` as the source of truth for
/// task metadata (id, requirement, ACs, owner, labels, docs).
pub mod tasks_def;

/// Helpers for reading and writing task status to `tasks_state.yaml`.
///
/// This module keeps mutable state (Todo/InProgress/Done, etc.)
/// separate from the immutable spec so that governance writes do not
/// clobber human-authored YAML.
pub mod tasks_state;

use business_core::governance::{GovernanceError, GovernanceRepository, TaskId, TaskStatus};
use std::path::PathBuf;

/// Filesystem-backed implementation of the governance repository.
///
/// `FsGovernanceRepository` reads task definitions from the spec tree and
/// persists task status to `tasks_state.yaml` under the same root. It is
/// intended for:
/// - local development
/// - acceptance tests
/// - simple deployments that want transparent YAML state
///
/// For more advanced storage (database, API), implement `GovernanceRepository`
/// in a separate crate.
pub struct FsGovernanceRepository {
    state_file_path: PathBuf,
    tasks_file_path: PathBuf,
}

impl FsGovernanceRepository {
    /// Create a new filesystem governance repository rooted at `specs_dir`.
    ///
    /// The `specs_dir` should be the directory that contains `specs/tasks.yaml`
    /// and the companion `tasks_state.yaml` file. All read/write operations
    /// are resolved relative to this path.
    pub fn new(specs_dir: PathBuf) -> Self {
        Self {
            state_file_path: specs_dir.join("tasks_state.yaml"),
            tasks_file_path: specs_dir.join("tasks.yaml"),
        }
    }
}

/// Parse a task status string from tasks.yaml to TaskStatus enum
fn parse_task_status(status_str: &str) -> Option<TaskStatus> {
    match status_str.to_lowercase().as_str() {
        "todo" | "open" => Some(TaskStatus::Todo),
        "in_progress" | "inprogress" | "in-progress" => Some(TaskStatus::InProgress),
        "review" => Some(TaskStatus::Review),
        "done" | "closed" | "complete" | "completed" => Some(TaskStatus::Done),
        _ => None,
    }
}

impl GovernanceRepository for FsGovernanceRepository {
    fn load_task(
        &self,
        task_id: &TaskId,
    ) -> Result<business_core::governance::Task, GovernanceError> {
        let definitions = tasks_def::load_tasks_definitions(&self.tasks_file_path)
            .map_err(|e| GovernanceError::Io(std::io::Error::other(e)))?;

        let definition = definitions.get(task_id.0.as_str());

        // Load status from tasks_state.yaml, falling back to tasks.yaml definition
        let status = tasks_state::get_task_status(&self.state_file_path, task_id)
            .map_err(|e| GovernanceError::Io(std::io::Error::other(e)))?
            .or_else(|| {
                definition.and_then(|def| def.status.as_deref().and_then(parse_task_status))
            })
            .unwrap_or(TaskStatus::Todo);

        // Load title from tasks.yaml (or use ID as last resort)
        let title = definition.map(|def| def.title.clone()).unwrap_or_else(|| task_id.0.clone());

        Ok(business_core::governance::Task { id: task_id.clone(), title, status })
    }

    fn find_all_tasks(&self) -> Result<Vec<business_core::governance::Task>, GovernanceError> {
        // Load definitions from tasks.yaml (source of truth for task list)
        let definitions = tasks_def::load_tasks_definitions(&self.tasks_file_path)
            .map_err(|e| GovernanceError::Io(std::io::Error::other(e)))?;

        // Load status overrides from tasks_state.yaml (if exists)
        let state_map = tasks_state::get_all_tasks(&self.state_file_path)
            .map_err(|e| GovernanceError::Io(std::io::Error::other(e)))?;

        let tasks = definitions
            .into_iter()
            .map(|(task_id, def)| {
                let id = TaskId(task_id);

                // Use status from state file if exists, otherwise parse from definition
                let status = state_map
                    .get(&id)
                    .cloned()
                    .or_else(|| def.status.as_ref().and_then(|s| parse_task_status(s.as_str())))
                    .unwrap_or(TaskStatus::Todo);

                business_core::governance::Task { id, title: def.title, status }
            })
            .collect();

        Ok(tasks)
    }

    fn set_task_status(&self, task_id: &TaskId, status: TaskStatus) -> Result<(), GovernanceError> {
        tasks_state::update_task_status(&self.state_file_path, task_id.clone(), status)
            .map_err(|e| GovernanceError::Io(std::io::Error::other(e)))
    }
}

//! Task definition loader for filesystem-based governance.
//!
//! This module loads strongly-typed task definitions from a YAML file
//! (typically `specs/tasks.yaml`) and exposes them as `TaskDefinition`
//! values keyed by task id.

use serde::Deserialize;
use std::collections::HashMap;

/// Top-level representation of the tasks definition file.
///
/// This mirrors the YAML structure used for `specs/tasks.yaml` and
/// is intended to be deserialized directly from disk.
#[derive(Debug, Deserialize, Clone)]
pub struct TasksFile {
    /// Schema version of the tasks file format (e.g. `"1.0"`).
    pub schema_version: String,
    /// Template/kernel version this tasks file was authored against.
    ///
    /// This is used for sanity checks when upgrading the kernel or
    /// comparing fork state.
    pub template_version: String,
    /// All task definitions declared in the file.
    pub tasks: Vec<TaskDefinition>,
}

/// Canonical definition of a single task from the spec tree.
///
/// This is the "read-only" view of a task: it describes what the task is,
/// which requirement and ACs it relates to, and how it should be presented.
#[derive(Debug, Deserialize, Clone)]
pub struct TaskDefinition {
    /// Unique task identifier (e.g. `TASK-HINT-001`).
    pub id: String,
    /// Human-readable title for the task.
    pub title: String,
    /// Requirement id this task is primarily associated with (e.g. `REQ-TPL-HEALTH`).
    pub requirement: String,
    /// Acceptance criteria this task helps satisfy.
    #[serde(default)]
    pub acs: Vec<String>,
    /// Optional current status snapshot from the spec (`Todo`, `InProgress`, `Done`, etc.).
    ///
    /// This is descriptive; the authoritative mutable status lives in `tasks_state.yaml`.
    #[serde(default)]
    pub status: Option<String>,
    /// Optional owner identifier (team or person).
    #[serde(default)]
    pub owner: Option<String>,
    /// Free-form labels for filtering and hints (e.g. `["security", "v3"]`).
    #[serde(default)]
    pub labels: Vec<String>,
    /// Short summary or description of the task.
    #[serde(default)]
    pub summary: Option<String>,
    /// Recommended DevEx flows to use for this task (e.g. `["governed-feature-dev"]`).
    #[serde(default)]
    pub recommended_flows: Vec<String>,
    /// Linked documentation for the task (design docs, plans, runbooks).
    #[serde(default)]
    pub docs: TaskDocs,
}

/// Structured document references associated with a task.
///
/// These fields allow the governance UI and agents to surface the
/// right design and plan docs alongside the task.
#[derive(Debug, Deserialize, Clone, Default)]
pub struct TaskDocs {
    /// Design documents relevant to this task (paths or URLs).
    #[serde(default)]
    pub design: Vec<String>,
    /// Plan / implementation documents relevant to this task.
    #[serde(default)]
    pub plan: Vec<String>,
}

/// Load task definitions from a YAML file on disk.
///
/// `path` should point to a tasks definition file (usually `specs/tasks.yaml`).
/// On success this returns a map from task id to `TaskDefinition`.
///
/// The error string is suitable for displaying in CLI error messages and
/// propagating up as a `GovernanceError` cause.
pub fn load_tasks_definitions(
    path: &std::path::Path,
) -> Result<HashMap<String, TaskDefinition>, String> {
    let content =
        std::fs::read_to_string(path).map_err(|e| format!("Failed to read tasks.yaml: {}", e))?;

    let tasks_file: TasksFile =
        serde_yaml::from_str(&content).map_err(|e| format!("Failed to parse tasks.yaml: {}", e))?;

    let mut map = HashMap::new();
    for task in tasks_file.tasks {
        map.insert(task.id.clone(), task);
    }

    Ok(map)
}

//! Persistence for task execution state (`tasks_state.yaml`).
//!
//! This module tracks the *current* status of tasks (Todo, InProgress,
//! Review, Done, etc.) separately from the immutable task definitions.
//! It is the write-layer used by `FsGovernanceRepository`.

use business_core::governance::{TaskId, TaskStatus};
use fs2::FileExt;
use serde::{Deserialize, Serialize};
use std::collections::HashMap;
use std::fs::{self, OpenOptions};
use std::io::{Read, Seek, SeekFrom, Write};
use std::path::Path;

/// In-memory representation of persisted task status.
///
/// This mirrors the `tasks_state.yaml` file and is used to read and
/// write the set of task ids and their current `TaskStatus` values.
#[derive(Debug, Clone, Serialize, Deserialize, Default)]
pub struct TasksState {
    /// Map of task ids to their current status.
    pub tasks: HashMap<TaskId, TaskStatus>,
}

/// Update the status of a single task in `tasks_state.yaml`.
///
/// - `path` points to the `tasks_state.yaml` file.
/// - `task_id` is the task being updated.
/// - `status` is the new state (Todo/InProgress/Review/Done).
///
/// If the file does not exist yet it will be created. Existing entries
/// for other tasks are preserved.
#[allow(clippy::suspicious_open_options)]
pub fn update_task_status(
    path: &Path,
    task_id: TaskId,
    status: TaskStatus,
) -> Result<(), Box<dyn std::error::Error + Send + Sync>> {
    // Ensure directory exists
    if let Some(parent) = path.parent() {
        fs::create_dir_all(parent)?;
    }

    // Open file with read/write access, create if not exists
    let mut file = OpenOptions::new().read(true).write(true).create(true).open(path)?;

    // Lock the file for exclusive access
    file.lock_exclusive()?;

    // Read content
    let mut content = String::new();
    file.read_to_string(&mut content)?;

    // Parse or default
    let mut state: TasksState = if content.trim().is_empty() {
        TasksState::default()
    } else {
        serde_yaml::from_str(&content).unwrap_or_default()
    };

    // Update state
    state.tasks.insert(task_id, status);

    // Serialize
    let new_content = serde_yaml::to_string(&state)?;

    // Write back
    file.set_len(0)?;
    file.seek(SeekFrom::Start(0))?;
    file.write_all(new_content.as_bytes())?;

    // Unlock (optional as closing the file unlocks it, but explicit is fine)
    file.unlock()?;

    Ok(())
}

/// Look up the persisted status of a single task.
///
/// Returns:
/// - `Ok(Some(status))` if the task has a recorded state,
/// - `Ok(None)` if the task has no entry yet,
/// - `Err(_)` if the state file could not be read or parsed.
pub fn get_task_status(
    path: &Path,
    task_id: &TaskId,
) -> Result<Option<TaskStatus>, Box<dyn std::error::Error + Send + Sync>> {
    if !path.exists() {
        return Ok(None);
    }

    let mut file = OpenOptions::new().read(true).open(path)?;

    // Shared lock for reading
    file.lock_shared()?;

    let mut content = String::new();
    file.read_to_string(&mut content)?;

    file.unlock()?;

    if content.trim().is_empty() {
        return Ok(None);
    }

    let state: TasksState = serde_yaml::from_str(&content).unwrap_or_default();
    Ok(state.tasks.get(task_id).cloned())
}

/// Load the current status for all tasks from `tasks_state.yaml`.
///
/// This is used by APIs and UIs that need to show a dashboard of
/// all tasks and their current state.
pub fn get_all_tasks(
    path: &Path,
) -> Result<HashMap<TaskId, TaskStatus>, Box<dyn std::error::Error + Send + Sync>> {
    if !path.exists() {
        return Ok(HashMap::new());
    }

    let mut file = OpenOptions::new().read(true).open(path)?;
    file.lock_shared()?;

    let mut content = String::new();
    file.read_to_string(&mut content)?;

    file.unlock()?;

    if content.trim().is_empty() {
        return Ok(HashMap::new());
    }

    let state: TasksState = serde_yaml::from_str(&content).unwrap_or_default();
    Ok(state.tasks)
}

//! Integration tests for the FsGovernanceRepository adapter.

use adapters_spec_fs::FsGovernanceRepository;
use business_core::governance::{GovernanceRepository, TaskId, TaskStatus};
use std::fs;

#[test]
fn test_set_task_status_persists() {
    // Setup temp dir
    let temp_dir = tempfile::tempdir().unwrap();
    let specs_dir = temp_dir.path().to_path_buf();

    // Initialize repo
    let repo = FsGovernanceRepository::new(specs_dir.clone());

    // Define task and status
    let task_id = TaskId("TASK-123".to_string());
    let status = TaskStatus::InProgress;

    // Set status
    repo.set_task_status(&task_id, status.clone()).unwrap();

    // Verify file exists
    let state_file = specs_dir.join("tasks_state.yaml");
    assert!(state_file.exists());

    // Verify content
    let content = fs::read_to_string(state_file).unwrap();
    assert!(content.contains("TASK-123"));
    assert!(content.contains("InProgress"));

    // Update status
    let new_status = TaskStatus::Done;
    repo.set_task_status(&task_id, new_status.clone()).unwrap();

    // Verify update
    let content = fs::read_to_string(specs_dir.join("tasks_state.yaml")).unwrap();
    assert!(content.contains("Done"));
}

#[test]
fn load_task_falls_back_to_tasks_yaml_status() {
    // Setup temp dir with tasks.yaml but no tasks_state.yaml entry
    let temp_dir = tempfile::tempdir().unwrap();
    let specs_dir = temp_dir.path().to_path_buf();

    let tasks_yaml = r#"
schema_version: "1.0"
template_version: "1.0"
tasks:
  - id: TASK-STATELESS
    title: "Task without state"
    requirement: REQ-TEST
    status: in_progress
    acs: []
    labels: []
    summary: "Example"
    recommended_flows: []
    docs:
      design: []
      plan: []
"#;

    fs::create_dir_all(&specs_dir).unwrap();
    fs::write(specs_dir.join("tasks.yaml"), tasks_yaml.trim()).unwrap();

    let repo = FsGovernanceRepository::new(specs_dir.clone());
    let task = repo.load_task(&TaskId("TASK-STATELESS".to_string())).unwrap();

    assert_eq!(task.status, TaskStatus::InProgress);
}

use axum::{
    Json, Router,
    extract::{Query, State},
    routing::get,
};
use business_core::governance::TaskService;
use serde::{Deserialize, Serialize};
use spec_runtime::hints::{self, HintEngine, HintLinks, HintReason, HintTarget};

use crate::AppState;

#[derive(Debug, Serialize, Deserialize)]
pub struct RecommendedStep {
    pub kind: String,
    pub value: String,
}

/// Wire format for agent hints (AC-TPL-AGENT-HINTS-SCHEMA).
///
/// Uses the canonical `Hint*` types from `spec_runtime::hints` for schema fields,
/// plus convenience fields for backward compatibility with AC-TPL-AGENT-HINTS.
#[derive(Debug, Serialize, Deserialize)]
pub struct AgentHint {
    // Full schema fields (AC-TPL-AGENT-HINTS-SCHEMA) - canonical types from spec_runtime
    pub id: String,
    pub kind: String,
    pub priority: String,
    pub status: String,
    pub reason: HintReason,
    pub target: HintTarget,
    pub tags: Vec<String>,
    pub links: HintLinks,

    // Convenience fields (backward compatibility with AC-TPL-AGENT-HINTS)
    pub task_id: String,
    pub title: String,
    pub owner: String,
    pub labels: Vec<String>,
    pub requirement_ids: Vec<String>,
    pub ac_ids: Vec<String>,
    pub recommended_sequence: Vec<RecommendedStep>,
}

#[derive(Debug, Serialize, Deserialize)]
pub struct AgentHintsResponse {
    pub hints: Vec<AgentHint>,
}

#[derive(Debug, Deserialize)]
pub struct HintsFilters {
    pub owner: Option<String>,
    pub label: Option<String>,
    pub requirement: Option<String>,
}

pub fn router(state: AppState) -> Router<AppState> {
    Router::new().route("/platform/agent/hints", get(agent_hints)).with_state(state)
}

async fn agent_hints(
    State(state): State<AppState>,
    Query(filters): Query<HintsFilters>,
) -> Result<Json<AgentHintsResponse>, crate::AppError> {
    let service = TaskService::new(state.governance_repo.clone());
    let tasks = service.list_tasks().map_err(|e| {
        crate::AppError::new(
            axum::http::StatusCode::INTERNAL_SERVER_ERROR,
            crate::ErrorCode::InternalError,
            format!("Failed to list tasks: {}", e),
        )
    })?;

    // Load full task definitions from tasks.yaml for rich metadata
    let tasks_path = state.workspace_root.join("specs/tasks.yaml");
    let task_definitions = adapters_spec_fs::tasks_def::load_tasks_definitions(&tasks_path)
        .map_err(|e| {
            crate::AppError::new(
                axum::http::StatusCode::INTERNAL_SERVER_ERROR,
                crate::ErrorCode::InternalError,
                format!("Failed to load task definitions: {}", e),
            )
        })?;

    // Load AC coverage from feature_status.md
    let feature_status_path = state.workspace_root.join("docs/feature_status.md");
    let ac_index = hints::parse_feature_status(&feature_status_path).map_err(|e| {
        crate::AppError::new(
            axum::http::StatusCode::INTERNAL_SERVER_ERROR,
            crate::ErrorCode::InternalError,
            format!("Failed to parse feature_status.md: {}", e),
        )
    })?;

    // Load devex_flows.yaml for flow-based command sequences
    let devex_path = state.workspace_root.join("specs/devex_flows.yaml");
    let devex_content = std::fs::read_to_string(&devex_path).map_err(|e| {
        crate::AppError::new(
            axum::http::StatusCode::INTERNAL_SERVER_ERROR,
            crate::ErrorCode::InternalError,
            format!("Failed to read devex_flows.yaml: {}", e),
        )
    })?;
    let devex_spec: serde_yaml::Value = serde_yaml::from_str(&devex_content).map_err(|e| {
        crate::AppError::new(
            axum::http::StatusCode::INTERNAL_SERVER_ERROR,
            crate::ErrorCode::InternalError,
            format!("Failed to parse devex_flows.yaml: {}", e),
        )
    })?;

    // Convert governance tasks to spec_runtime tasks
    let runtime_tasks: Vec<spec_runtime::Task> = tasks
        .iter()
        .filter_map(|t| {
            let task_id = t.id.0.clone();
            let definition = task_definitions.get(&task_id)?;

            Some(spec_runtime::Task {
                id: task_id,
                title: definition.title.clone(),
                status: format!("{:?}", t.status),
                requirement: definition.requirement.clone(),
                acs: definition.acs.clone(),
                labels: definition.labels.clone(),
                owner: definition.owner.clone(),
                docs: None,
                summary: definition.summary.clone().unwrap_or_default(),
                recommended_flows: definition.recommended_flows.clone(),
                depends_on: vec![],
            })
        })
        .collect();

    // Create HintEngine with AC coverage
    let engine = HintEngine::new(ac_index, runtime_tasks);
    let hint_engine_hints = engine.task_hints();

    // Convert HintEngine hints to AgentHints and build recommended sequences
    let mut hints: Vec<AgentHint> = hint_engine_hints
        .iter()
        .filter_map(|hint| {
            // Only include Todo and InProgress hints (HintEngine filters these)
            if !matches!(hint.status, hints::HintStatus::Open | hints::HintStatus::InProgress) {
                return None;
            }

            let task_id = match &hint.target {
                hints::HintTarget::Task { id } => id.clone(),
                _ => return None,
            };

            let definition = task_definitions.get(&task_id)?;

            // Build recommended sequence from recommended_flows
            let recommended_sequence = build_recommended_sequence(
                &task_id,
                &definition.recommended_flows,
                &definition.acs,
                &devex_spec,
            );

            // Convert status
            let status_str = match hint.status {
                hints::HintStatus::Open => "open".to_string(),
                hints::HintStatus::InProgress => "in_progress".to_string(),
                hints::HintStatus::Done => "done".to_string(),
            };

            // Convert priority
            let priority_str = match hint.priority {
                hints::HintPriority::Low => "low".to_string(),
                hints::HintPriority::Medium => "medium".to_string(),
                hints::HintPriority::High => "high".to_string(),
            };

            // Convert kind
            let kind_str = match hint.kind {
                hints::HintKind::Task => "task".to_string(),
                hints::HintKind::Governance => "governance".to_string(),
                hints::HintKind::Policy => "policy".to_string(),
                hints::HintKind::Flow => "flow".to_string(),
            };

            // Reuse links and target directly from core hint (no conversion needed)
            let links = hint.links.clone();
            let target = hint.target.clone();

            Some(AgentHint {
                // Full schema fields - reuse core types directly
                id: hint.id.clone(),
                kind: kind_str,
                priority: priority_str,
                status: status_str,
                reason: hint.reason.clone(),
                target,
                tags: hint.tags.clone(),
                links,

                // Backward-compatible convenience fields
                task_id,
                title: hint.title.clone(),
                owner: definition.owner.clone().unwrap_or_else(|| "unassigned".to_string()),
                labels: hint.tags.clone(), // Mirror tags for legacy BDD/UI compatibility
                requirement_ids: vec![definition.requirement.clone()],
                ac_ids: definition.acs.clone(),
                recommended_sequence,
            })
        })
        .collect();

    // Apply filters
    hints.retain(|hint| {
        // Filter by owner
        if let Some(ref owner_filter) = filters.owner
            && !hint.owner.eq_ignore_ascii_case(owner_filter)
        {
            return false;
        }

        // Filter by label
        if let Some(ref label_filter) = filters.label
            && !hint.labels.iter().any(|l| l.eq_ignore_ascii_case(label_filter))
        {
            return false;
        }

        // Filter by requirement
        if let Some(ref req_filter) = filters.requirement
            && !hint.requirement_ids.iter().any(|r| r.eq_ignore_ascii_case(req_filter))
        {
            return false;
        }

        true
    });

    // Sort by: 1) status (in_progress before open), 2) priority label, 3) ID
    hints.sort_by(|a, b| {
        // Primary: status (in_progress before open)
        let status_order_a = if a.status == "in_progress" { 0 } else { 1 };
        let status_order_b = if b.status == "in_progress" { 0 } else { 1 };

        match status_order_a.cmp(&status_order_b) {
            std::cmp::Ordering::Equal => {
                // Secondary: priority label (high > medium > low > none)
                let priority_a = get_priority_order(&a.labels);
                let priority_b = get_priority_order(&b.labels);

                match priority_a.cmp(&priority_b) {
                    std::cmp::Ordering::Equal => {
                        // Tertiary: ID (alphabetical)
                        a.task_id.cmp(&b.task_id)
                    }
                    other => other,
                }
            }
            other => other,
        }
    });

    Ok(Json(AgentHintsResponse { hints }))
}

/// Helper function to determine priority order from labels
/// Returns 0 for highest priority (priority:high), higher numbers for lower priority
fn get_priority_order(labels: &[String]) -> u8 {
    for label in labels {
        let label_lower = label.to_ascii_lowercase();
        if label_lower == "priority:high" || label_lower == "high" {
            return 0;
        } else if label_lower == "priority:medium" || label_lower == "medium" {
            return 1;
        } else if label_lower == "priority:low" || label_lower == "low" {
            return 2;
        }
    }
    // No priority label = lowest priority
    3
}

/// Build recommended command sequence from task's recommended_flows
fn build_recommended_sequence(
    task_id: &str,
    recommended_flows: &[String],
    ac_ids: &[String],
    devex_spec: &serde_yaml::Value,
) -> Vec<RecommendedStep> {
    let mut sequence = Vec::new();

    // Extract flows map from devex_spec
    let flows = match devex_spec.get("flows") {
        Some(serde_yaml::Value::Mapping(m)) => m,
        _ => return sequence,
    };

    // Process each recommended flow
    for flow_name in recommended_flows {
        if let Some(flow_value) = flows.get(flow_name)
            && let Some(steps_value) = flow_value.get("steps")
            && let Some(steps_seq) = steps_value.as_sequence()
        {
            // Add each step as a command
            for step in steps_seq {
                if let Some(cmd) = step.as_str() {
                    let command_value = match cmd {
                        // Special handling for common commands with task-specific params
                        "bundle" => format!("cargo xtask bundle {}", task_id),
                        "test-ac" => {
                            if let Some(first_ac) = ac_ids.first() {
                                format!("cargo xtask test-ac {}", first_ac)
                            } else {
                                format!("cargo xtask {}", cmd)
                            }
                        }
                        "bdd" => "cargo xtask bdd".to_string(),
                        "selftest" => "cargo xtask selftest".to_string(),
                        "ac-new" => "cargo xtask ac-new".to_string(),
                        "adr-new" => "cargo xtask adr-new".to_string(),
                        "adr-check" => "cargo xtask adr-check".to_string(),
                        "audit" => "cargo xtask audit".to_string(),
                        "release-prepare" => "cargo xtask release-prepare".to_string(),
                        "release-verify" => "cargo xtask release-verify".to_string(),
                        _ => format!("cargo xtask {}", cmd),
                    };

                    sequence.push(RecommendedStep {
                        kind: "command".to_string(),
                        value: command_value,
                    });
                }
            }
        }
    }

    sequence
}

//! Error handling with observability and correlation
//!
//! This module provides a comprehensive error type that supports:
//! - Machine-readable error codes
//! - AC ID and Feature ID tracking (for product/feature correlation)
//! - Structured logging with correlation fields
//! - Proper HTTP responses with JSON error bodies
//! - Request ID correlation
//!
//! # Design Philosophy
//!
//! Errors should be:
//! 1. **Actionable**: Include enough context to debug issues
//! 2. **Structured**: Use typed fields instead of string concatenation
//! 3. **Correlated**: Include request ID, AC ID, feature ID for tracing
//! 4. **Secure**: Don't leak internal details to clients
//! 5. **Observable**: Log errors with structured data for analysis
//!
//! # Example Usage
//!
//! ```rust,ignore
//! use crate::errors::{AppError, ErrorCode};
//!
//! // Simple error
//! return Err(AppError::bad_request("Invalid amount"));
//!
//! // Error with code and context
//! return Err(AppError::validation_error(
//!     ErrorCode::InvalidAmount,
//!     "Amount must be greater than 0"
//! ).with_context("amount_cents", payload.amount_cents));
//!
//! // Error with AC/Feature tracking
//! return Err(AppError::business_logic_error(
//!     ErrorCode::RefundNotEligible,
//!     "Order not eligible for refund"
//! ).with_ac_id("AC-123")
//!   .with_feature_id("FT-456"));
//! ```

use axum::{
    Json,
    extract::rejection::JsonRejection,
    http::{HeaderValue, StatusCode, header::HeaderName},
    response::{IntoResponse, Response},
};
use serde::Serialize;
use std::collections::HashMap;
use tracing::{error, warn};

use crate::middleware::request_id::RequestId;

/// Machine-readable error codes
///
/// These codes allow clients to programmatically handle different error scenarios
/// without parsing error messages. They also help with:
/// - Metrics aggregation (count errors by code)
/// - Alert rules (alert on specific error codes)
/// - Client-side error handling (show appropriate UI based on code)
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize)]
#[serde(rename_all = "SCREAMING_SNAKE_CASE")]
pub enum ErrorCode {
    // Validation errors (4xx)
    InvalidRequest,
    InvalidAmount,
    MissingField,
    InvalidFormat,
    Unauthorized,

    // Business logic errors (4xx)
    RefundNotEligible,
    OrderNotFound,
    InsufficientFunds,
    DuplicateRequest,

    // System errors (5xx)
    InternalError,
    ServiceUnavailable,
    DatabaseError,
    ExternalServiceError,
    // Add more as needed for your domain
}

impl std::fmt::Display for ErrorCode {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            ErrorCode::InvalidRequest => write!(f, "INVALID_REQUEST"),
            ErrorCode::InvalidAmount => write!(f, "INVALID_AMOUNT"),
            ErrorCode::MissingField => write!(f, "MISSING_FIELD"),
            ErrorCode::InvalidFormat => write!(f, "INVALID_FORMAT"),
            ErrorCode::Unauthorized => write!(f, "UNAUTHORIZED"),
            ErrorCode::RefundNotEligible => write!(f, "REFUND_NOT_ELIGIBLE"),
            ErrorCode::OrderNotFound => write!(f, "ORDER_NOT_FOUND"),
            ErrorCode::InsufficientFunds => write!(f, "INSUFFICIENT_FUNDS"),
            ErrorCode::DuplicateRequest => write!(f, "DUPLICATE_REQUEST"),
            ErrorCode::InternalError => write!(f, "INTERNAL_ERROR"),
            ErrorCode::ServiceUnavailable => write!(f, "SERVICE_UNAVAILABLE"),
            ErrorCode::DatabaseError => write!(f, "DATABASE_ERROR"),
            ErrorCode::ExternalServiceError => write!(f, "EXTERNAL_SERVICE_ERROR"),
        }
    }
}

/// Application error with full observability support
///
/// This error type includes:
/// - HTTP status code (for response)
/// - Error code (for clients and metrics)
/// - User message (safe to show to clients)
/// - Internal context (for logging, not shown to clients)
/// - AC ID and Feature ID (for product tracking)
/// - Request ID (for correlation - AC-TPL-004)
#[derive(Debug)]
pub struct AppError {
    /// HTTP status code to return
    status: StatusCode,
    /// Machine-readable error code
    code: ErrorCode,
    /// User-facing error message (safe to expose)
    message: String,
    /// Internal context for debugging (logged but not exposed to clients)
    context: HashMap<String, serde_json::Value>,
    /// AC (Acceptance Criteria) ID for tracking features
    ac_id: Option<String>,
    /// Feature ID for tracking which feature this relates to
    feature_id: Option<String>,
    /// Request ID for correlation (AC-TPL-004)
    /// If None, a new UUID will be generated when converting to response
    request_id: Option<String>,
}

impl AppError {
    /// Create a new error with status, code, and message
    pub fn new(status: StatusCode, code: ErrorCode, message: impl Into<String>) -> Self {
        Self {
            status,
            code,
            message: message.into(),
            context: HashMap::new(),
            ac_id: None,
            feature_id: None,
            request_id: None,
        }
    }

    /// Create a bad request error (400)
    pub fn bad_request(message: impl Into<String>) -> Self {
        Self::new(StatusCode::BAD_REQUEST, ErrorCode::InvalidRequest, message)
    }

    /// Create a validation error (400)
    pub fn validation_error(code: ErrorCode, message: impl Into<String>) -> Self {
        Self::new(StatusCode::BAD_REQUEST, code, message)
    }

    /// Create a business logic error (422 Unprocessable Entity)
    pub fn business_logic_error(code: ErrorCode, message: impl Into<String>) -> Self {
        Self::new(StatusCode::UNPROCESSABLE_ENTITY, code, message)
    }

    /// Create a not found error (404)
    pub fn not_found(message: impl Into<String>) -> Self {
        Self::new(StatusCode::NOT_FOUND, ErrorCode::OrderNotFound, message)
    }

    /// Create an internal server error (500)
    pub fn internal_error(message: impl Into<String>) -> Self {
        Self::new(StatusCode::INTERNAL_SERVER_ERROR, ErrorCode::InternalError, message)
    }

    /// Add context field for debugging
    ///
    /// Context is logged but not exposed to clients
    pub fn with_context(mut self, key: impl Into<String>, value: impl Serialize) -> Self {
        if let Ok(json_value) = serde_json::to_value(value) {
            self.context.insert(key.into(), json_value);
        }
        self
    }

    /// Add AC (Acceptance Criteria) ID
    ///
    /// Used to track which acceptance criteria this error relates to
    pub fn with_ac_id(mut self, ac_id: impl Into<String>) -> Self {
        self.ac_id = Some(ac_id.into());
        self
    }

    /// Add Feature ID
    ///
    /// Used to track which feature this error relates to
    pub fn with_feature_id(mut self, feature_id: impl Into<String>) -> Self {
        self.feature_id = Some(feature_id.into());
        self
    }

    /// Add Request ID (AC-TPL-004)
    ///
    /// Used for distributed tracing and correlation.
    /// If not set, a UUID will be generated automatically.
    pub fn with_request_id(mut self, request_id: impl Into<String>) -> Self {
        self.request_id = Some(request_id.into());
        self
    }

    /// Log the error with structured fields
    fn log_error(&self) {
        // Determine if this is a client error (4xx) or server error (5xx)
        let is_server_error = self.status.is_server_error();

        // Create structured log event
        if is_server_error {
            // Server errors are more severe - log as error level
            error!(
                error_code = %self.code,
                status_code = %self.status.as_u16(),
                message = %self.message,
                context = ?self.context,
                ac_id = ?self.ac_id,
                feature_id = ?self.feature_id,
                "Internal server error occurred"
            );
        } else {
            // Client errors are expected - log as warn level
            warn!(
                error_code = %self.code,
                status_code = %self.status.as_u16(),
                message = %self.message,
                context = ?self.context,
                ac_id = ?self.ac_id,
                feature_id = ?self.feature_id,
                "Client error occurred"
            );
        }
    }
}

/// JSON error response body
///
/// This is what clients receive when an error occurs.
/// Matches the ErrorResponse schema in openapi.yaml (AC-TPL-003).
#[derive(Debug, Serialize)]
struct ErrorResponse {
    /// Machine-readable error code (required by AC-TPL-003)
    error: String,
    /// Human-readable error message (required by AC-TPL-003)
    message: String,
    /// Request ID for correlation (required by AC-TPL-003, AC-TPL-004)
    #[serde(rename = "requestId")]
    request_id: String,
    /// Optional AC ID (for debugging/tracking)
    #[serde(skip_serializing_if = "Option::is_none")]
    ac_id: Option<String>,
    /// Optional Feature ID (for debugging/tracking)
    #[serde(skip_serializing_if = "Option::is_none")]
    feature_id: Option<String>,
    // Note: context is NOT included (internal only)
}

impl IntoResponse for AppError {
    fn into_response(self) -> Response {
        // Log the error with full context
        self.log_error();

        // Get or generate request ID (AC-TPL-004)
        let request_id =
            self.request_id.clone().unwrap_or_else(|| RequestId::generate().to_string());

        // Create client-safe response matching ErrorResponse schema (AC-TPL-003)
        let body = Json(ErrorResponse {
            error: self.code.to_string(),
            message: self.message.clone(),
            request_id: request_id.clone(),
            ac_id: self.ac_id.clone(),
            feature_id: self.feature_id.clone(),
        });

        // Create response with status code
        let mut response = (self.status, body).into_response();

        // Add X-Request-ID header (AC-TPL-004)
        if let Ok(header_value) = HeaderValue::from_str(&request_id) {
            response.headers_mut().insert(HeaderName::from_static("x-request-id"), header_value);
        }

        response
    }
}

/// Convert JSON rejection errors to AppError
///
/// This allows us to handle JSON parsing errors consistently
impl From<JsonRejection> for AppError {
    fn from(rejection: JsonRejection) -> Self {
        AppError::validation_error(
            ErrorCode::InvalidRequest,
            format!("Invalid JSON: {}", rejection),
        )
    }
}

impl From<business_core::governance::GovernanceError> for AppError {
    fn from(error: business_core::governance::GovernanceError) -> Self {
        use business_core::governance::GovernanceError::*;
        match error {
            TaskNotFound(id) => AppError::not_found(format!("Task not found: {:?}", id)),
            InvalidTransition { from, to } => AppError::internal_error(format!(
                "Invalid status transition from {:?} to {:?}",
                from, to
            )),
            Lock(msg) => AppError::internal_error(format!("Lock error: {}", msg)),
            Io(e) => AppError::internal_error(format!("IO error: {}", e)),
            Serialization(msg) => AppError::internal_error(format!("Serialization error: {}", msg)),
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_error_code_display() {
        assert_eq!(ErrorCode::InvalidAmount.to_string(), "INVALID_AMOUNT");
        assert_eq!(ErrorCode::RefundNotEligible.to_string(), "REFUND_NOT_ELIGIBLE");
    }

    #[test]
    fn test_bad_request_error() {
        let error = AppError::bad_request("Invalid input");
        assert_eq!(error.status, StatusCode::BAD_REQUEST);
        assert_eq!(error.code, ErrorCode::InvalidRequest);
        assert_eq!(error.message, "Invalid input");
    }

    #[test]
    fn test_error_with_context() {
        let error = AppError::validation_error(ErrorCode::InvalidAmount, "Amount must be positive")
            .with_context("amount", -100)
            .with_context("field", "amount_cents");

        assert!(error.context.contains_key("amount"));
        assert!(error.context.contains_key("field"));
    }

    #[test]
    fn test_error_with_ac_and_feature() {
        let error =
            AppError::business_logic_error(ErrorCode::RefundNotEligible, "Order not refundable")
                .with_ac_id("AC-123")
                .with_feature_id("FT-456");

        assert_eq!(error.ac_id, Some("AC-123".to_string()));
        assert_eq!(error.feature_id, Some("FT-456".to_string()));
    }

    #[test]
    fn test_error_serialization() {
        let error = AppError::validation_error(ErrorCode::InvalidAmount, "Amount must be positive")
            .with_ac_id("AC-123")
            .with_feature_id("FT-456")
            .with_request_id("req-test-123");

        let response = ErrorResponse {
            error: error.code.to_string(),
            message: error.message.clone(),
            request_id: error.request_id.clone().unwrap_or_default(),
            ac_id: error.ac_id.clone(),
            feature_id: error.feature_id.clone(),
        };

        let json = serde_json::to_string(&response).unwrap();
        assert!(json.contains("INVALID_AMOUNT"));
        assert!(json.contains("Amount must be positive"));
        assert!(json.contains("req-test-123"));
        assert!(json.contains("AC-123"));
        assert!(json.contains("FT-456"));
        // Verify it uses "error" not "code" (AC-TPL-003)
        assert!(json.contains(r#""error":"INVALID_AMOUNT""#));
        // Verify it uses "requestId" not "request_id" (AC-TPL-003)
        assert!(json.contains(r#""requestId":"req-test-123""#));
    }

    #[test]
    fn test_governance_invalid_transition_maps_to_server_error() {
        use business_core::governance::TaskStatus;

        let app_error: AppError = business_core::governance::GovernanceError::InvalidTransition {
            from: TaskStatus::Todo,
            to: TaskStatus::Done,
        }
        .into();

        assert_eq!(app_error.status, StatusCode::INTERNAL_SERVER_ERROR);
        assert!(
            app_error.message.contains("Invalid status transition"),
            "message should mention status transition, got: {}",
            app_error.message
        );
    }
}

