//! Core business logic for the Rust-as-Spec platform cell.
//!
//! This crate defines the domain model and governance traits used by the
//! rest of the workspace, including:
//! - `TaskRepository` – persistence boundary for task state
//! - `Task` types (from `model` crate) – core task lifecycle
//!
//! Adapters (HTTP handlers, database drivers, event systems) implement these
//! ports to provide concrete storage and transport. The kernel treats this crate
//! as the source of truth for governance semantics.
//!
//! ## Architecture
//!
//! - No dependencies on HTTP, database, or other infrastructure adapters
//! - Adapters (app-http, app-db, etc.) call core, never the reverse
//! - Core defines ports (traits), adapters implement them

/// Ports (interfaces) for task persistence and storage.
///
/// This module defines the boundary traits that adapters must implement.
pub mod ports {
    use model::Task;

    /// Port for task persistence.
    ///
    /// Adapters (e.g., filesystem, database) implement this trait to provide
    /// concrete task storage and retrieval.
    #[async_trait::async_trait]
    pub trait TaskRepository: Send + Sync {
        /// Save a new task to storage.
        async fn save(&self, task: &Task) -> Result<(), String>;

        /// Find a task by its unique ID.
        async fn find_by_id(&self, id: &str) -> Result<Option<Task>, String>;

        /// Retrieve all tasks from storage.
        async fn find_all(&self) -> Result<Vec<Task>, String>;

        /// Update a task's status by ID.
        async fn update_status(
            &self,
            id: &str,
            status: model::TaskStatus,
        ) -> Result<Option<Task>, String>;
    }
}

/// Use cases (application logic) for task operations.
///
/// This module contains the business logic functions that orchestrate
/// task creation, retrieval, and status updates using the repository port.
pub mod use_cases {
    use super::ports::TaskRepository;
    use model::{Task, TaskStatus};

    /// Create a new task with a given title.
    ///
    /// Generates a new UUID, sets the status to Pending, and saves the task.
    ///
    /// # Errors
    ///
    /// Returns an error if the repository save operation fails.
    pub async fn create_task(repo: &dyn TaskRepository, title: String) -> Result<Task, String> {
        let task = Task {
            id: uuid::Uuid::new_v4().to_string(),
            title,
            status: TaskStatus::Pending,
            created_at: chrono::Utc::now(),
        };
        repo.save(&task).await?;
        Ok(task)
    }

    /// Retrieve a task by its unique ID.
    ///
    /// # Errors
    ///
    /// Returns an error if the repository operation fails.
    pub async fn get_task(repo: &dyn TaskRepository, id: String) -> Result<Option<Task>, String> {
        repo.find_by_id(&id).await
    }

    /// List all tasks from the repository.
    ///
    /// # Errors
    ///
    /// Returns an error if the repository operation fails.
    pub async fn list_tasks(repo: &dyn TaskRepository) -> Result<Vec<Task>, String> {
        repo.find_all().await
    }

    /// Update a task's status by ID.
    ///
    /// # Errors
    ///
    /// Returns an error if the repository operation fails.
    pub async fn update_task_status(
        repo: &dyn TaskRepository,
        id: String,
        status: TaskStatus,
    ) -> Result<Option<Task>, String> {
        repo.update_status(&id, status).await
    }
}

/// Governance domain model for task management.
///
/// This module contains the core domain types for governance workflows,
/// including task states, transitions, and the governance repository trait.
pub mod governance {
    use serde::{Deserialize, Serialize};

    /// Task status in the governance workflow.
    ///
    /// Defines the allowed states and valid transitions for governance tasks.
    #[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
    pub enum TaskStatus {
        /// Task is not yet started.
        Todo,
        /// Task is actively being worked on.
        InProgress,
        /// Task is complete and awaiting review.
        Review,
        /// Task is fully complete and approved.
        Done,
    }

    impl TaskStatus {
        /// Check if a transition from the current status to a new status is valid.
        ///
        /// Allowed transitions:
        /// - Todo → InProgress
        /// - InProgress → Review (or back to Todo)
        /// - Review → Done (or back to InProgress)
        pub fn can_transition_to(&self, next: &TaskStatus) -> bool {
            use TaskStatus::*;
            match (self, next) {
                (Todo, InProgress) => true,
                (InProgress, Review) => true,
                (Review, Done) => true,
                (Review, InProgress) => true, // Backwards allowed
                (InProgress, Todo) => true,   // Backwards allowed
                _ => false,
            }
        }
    }

    /// A governance task with ID, title, and status.
    #[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
    pub struct Task {
        /// Unique task identifier.
        pub id: TaskId,
        /// Task title or description.
        pub title: String,
        /// Current workflow status.
        pub status: TaskStatus,
    }

    /// Unique identifier for a governance task.
    #[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]
    pub struct TaskId(pub String);

    /// Errors that can occur during governance operations.
    #[derive(Debug, thiserror::Error)]
    pub enum GovernanceError {
        /// IO error during repository operations.
        #[error("IO error: {0}")]
        Io(#[from] std::io::Error),
        /// Serialization/deserialization error.
        #[error("Serialization error: {0}")]
        Serialization(String),
        /// Task not found in the repository.
        #[error("Task not found: {0:?}")]
        TaskNotFound(TaskId),
        /// Lock acquisition failure.
        #[error("Lock error: {0}")]
        Lock(String),
        /// Invalid state transition attempted.
        #[error("Invalid transition from {from:?} to {to:?}")]
        InvalidTransition {
            /// Source status.
            from: TaskStatus,
            /// Target status.
            to: TaskStatus,
        },
    }

    /// Repository trait for governance task persistence.
    ///
    /// Adapters implement this trait to provide concrete storage mechanisms.
    pub trait GovernanceRepository: Send + Sync {
        /// Load a task by its ID.
        ///
        /// # Errors
        ///
        /// Returns [`GovernanceError::TaskNotFound`] if the task does not exist.
        fn load_task(&self, task_id: &TaskId) -> Result<Task, GovernanceError>;

        /// Retrieve all tasks from storage.
        ///
        /// # Errors
        ///
        /// Returns an error if the repository operation fails.
        fn find_all_tasks(&self) -> Result<Vec<Task>, GovernanceError>;

        /// Update a task's status.
        ///
        /// # Errors
        ///
        /// Returns an error if the task is not found or the update fails.
        fn set_task_status(
            &self,
            task_id: &TaskId,
            status: TaskStatus,
        ) -> Result<(), GovernanceError>;
    }

    impl GovernanceRepository for std::sync::Arc<dyn GovernanceRepository> {
        fn load_task(&self, task_id: &TaskId) -> Result<Task, GovernanceError> {
            (**self).load_task(task_id)
        }

        fn find_all_tasks(&self) -> Result<Vec<Task>, GovernanceError> {
            (**self).find_all_tasks()
        }

        fn set_task_status(
            &self,
            task_id: &TaskId,
            status: TaskStatus,
        ) -> Result<(), GovernanceError> {
            (**self).set_task_status(task_id, status)
        }
    }

    /// Service for managing task lifecycle and transitions.
    ///
    /// Orchestrates task operations and enforces state transition rules.
    pub struct TaskService<R: GovernanceRepository> {
        repo: R,
    }

    impl<R: GovernanceRepository> TaskService<R> {
        /// Create a new task service with the given repository.
        pub fn new(repo: R) -> Self {
            Self { repo }
        }

        /// Move a task to a new status, enforcing transition rules.
        ///
        /// # Errors
        ///
        /// Returns [`GovernanceError::InvalidTransition`] if the transition is not allowed.
        /// Returns [`GovernanceError::TaskNotFound`] if the task does not exist.
        pub fn move_task(
            &self,
            id: &TaskId,
            new_status: TaskStatus,
        ) -> Result<(), GovernanceError> {
            let mut task = self.repo.load_task(id)?;
            if !task.status.can_transition_to(&new_status) {
                return Err(GovernanceError::InvalidTransition {
                    from: task.status,
                    to: new_status,
                });
            }
            task.status = new_status.clone();
            self.repo.set_task_status(id, new_status)?;
            Ok(())
        }

        /// List all tasks from the repository.
        ///
        /// # Errors
        ///
        /// Returns an error if the repository operation fails.
        pub fn list_tasks(&self) -> Result<Vec<Task>, GovernanceError> {
            self.repo.find_all_tasks()
        }
    }

    #[cfg(test)]
    mod tests {
        use super::*;

        #[test]
        fn test_allowed_transitions() {
            assert!(TaskStatus::Todo.can_transition_to(&TaskStatus::InProgress));
            assert!(TaskStatus::InProgress.can_transition_to(&TaskStatus::Review));
            assert!(TaskStatus::Review.can_transition_to(&TaskStatus::Done));
            assert!(TaskStatus::Review.can_transition_to(&TaskStatus::InProgress));
        }

        #[test]
        fn test_forbidden_transitions() {
            assert!(!TaskStatus::Done.can_transition_to(&TaskStatus::Todo));
            assert!(!TaskStatus::Todo.can_transition_to(&TaskStatus::Done));
        }
    }
}

//! Shared types for the Rust-as-Spec platform cell.
//!
//! This crate contains data structures that are shared across the workspace
//! (core business logic, HTTP handlers, database drivers, UI, and governance logic).
//!
//! The goal is to keep cross-crate types centralized, so that changes to the
//! platform model are visible and reviewable in one place.
//!
//! ## Design principles
//!
//! - Lightweight: only pure data structures and value objects (no business logic)
//! - Reusable: can be serialized for HTTP/gRPC/storage without adaptation
//! - Stable: changes here ripple across the entire workspace
//!

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Task {
    pub id: String,
    pub title: String,
    pub status: TaskStatus,
    pub created_at: chrono::DateTime<chrono::Utc>,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum TaskStatus {
    Pending,
    InProgress,
    Completed,
}

//! Configuration structures for IaC orchestration

use crate::error::ConfigError;
use crate::validation;
use serde::{Deserialize, Serialize};
use std::collections::HashSet;
use std::path::{Path, PathBuf};

/// Main configuration structure for IaC orchestration
///
/// This structure defines all aspects of an IaC project including:
/// - Project metadata
/// - Deployment environments
/// - Validation rules
///
/// # Example
///
/// ```yaml
/// project:
///   name: my-project
///   workspace_root: .
///
/// environments:
///   - name: dev
///     manifests_path: infra/k8s/dev
///     requires_kustomize: false
///
/// validation:
///   check_git_repo: true
///   required_directories:
///     - specs
/// ```
#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
pub struct IaCConfig {
    /// Project-level information
    pub project: ProjectInfo,

    /// List of deployment environments (dev, staging, prod, etc.)
    #[serde(default)]
    pub environments: Vec<Environment>,

    /// Validation rules to enforce
    #[serde(default)]
    pub validation: ValidationRules,
}

impl IaCConfig {
    /// Load and validate configuration from a YAML file
    ///
    /// This method will:
    /// 1. Check if the file exists
    /// 2. Parse the YAML content
    /// 3. Validate the configuration structure
    /// 4. Run validation checks (if enabled)
    ///
    /// # Arguments
    ///
    /// * `path` - Path to the YAML configuration file
    ///
    /// # Returns
    ///
    /// Returns `Ok(IaCConfig)` if the file was successfully loaded and validated,
    /// or `Err(ConfigError)` with details about what went wrong.
    ///
    /// # Errors
    ///
    /// - [`ConfigError::FileNotFound`] if the file doesn't exist
    /// - [`ConfigError::FileReadError`] if the file can't be read
    /// - [`ConfigError::InvalidYaml`] if the YAML is malformed
    /// - Various validation errors if the configuration is invalid
    ///
    /// # Example
    ///
    /// ```no_run
    /// use rust_iac_config::IaCConfig;
    /// use std::path::Path;
    ///
    /// let config = IaCConfig::from_file(Path::new("iac-config.yaml"))?;
    /// println!("Loaded config for project: {}", config.project.name);
    /// # Ok::<(), rust_iac_config::ConfigError>(())
    /// ```
    pub fn from_file(path: &Path) -> Result<Self, ConfigError> {
        // Check file exists
        if !path.exists() {
            return Err(ConfigError::FileNotFound(path.to_path_buf()));
        }

        // Read file contents
        let contents = std::fs::read_to_string(path)
            .map_err(|e| ConfigError::file_read_error(path.to_path_buf(), e))?;

        // Parse YAML
        let mut config: IaCConfig =
            serde_yaml::from_str(&contents).map_err(|e| ConfigError::InvalidYaml(e.to_string()))?;

        // Resolve workspace_root relative to the config file location to avoid relying on the
        // process working directory (tests modify it).
        if config.project.workspace_root.is_relative() {
            let config_dir = path.parent().unwrap_or_else(|| Path::new("."));
            config.project.workspace_root = config_dir.join(&config.project.workspace_root);
        }

        // Validate the configuration
        config.validate()?;

        Ok(config)
    }

    /// Validate the configuration
    ///
    /// Checks:
    /// - Project name is not empty
    /// - No duplicate environment names
    /// - All required directories exist (if specified)
    /// - Git repository exists (if check_git_repo is true)
    /// - Environment configurations are valid
    fn validate(&self) -> Result<(), ConfigError> {
        // Validate project info
        if self.project.name.trim().is_empty() {
            return Err(ConfigError::missing_field(
                "project.name",
                "Provide a non-empty project name",
            ));
        }

        // Check for duplicate environment names
        let mut seen_envs = HashSet::new();
        for env in &self.environments {
            if !seen_envs.insert(&env.name) {
                return Err(ConfigError::DuplicateEnvironment(env.name.clone()));
            }
        }

        // Validate each environment
        for env in &self.environments {
            env.validate(&self.project.workspace_root)?;
        }

        // Run validation rules
        validation::validate_config(self)?;

        Ok(())
    }

    /// Find an environment by name
    ///
    /// # Arguments
    ///
    /// * `name` - The name of the environment to find (case-insensitive)
    ///
    /// # Returns
    ///
    /// Returns `Some(&Environment)` if found, `None` otherwise.
    ///
    /// # Example
    ///
    /// ```no_run
    /// # use rust_iac_config::IaCConfig;
    /// # use std::path::Path;
    /// # let config = IaCConfig::from_file(Path::new("config.yaml"))?;
    /// if let Some(env) = config.find_environment("dev") {
    ///     println!("Dev environment found at: {}", env.manifests_path.display());
    /// }
    /// # Ok::<(), rust_iac_config::ConfigError>(())
    /// ```
    pub fn find_environment(&self, name: &str) -> Option<&Environment> {
        self.environments.iter().find(|e| e.name.eq_ignore_ascii_case(name))
    }

    /// Get a list of all environment names
    ///
    /// # Returns
    ///
    /// A vector of environment names as strings.
    ///
    /// # Example
    ///
    /// ```no_run
    /// # use rust_iac_config::IaCConfig;
    /// # use std::path::Path;
    /// # let config = IaCConfig::from_file(Path::new("config.yaml"))?;
    /// let envs = config.environment_names();
    /// println!("Available environments: {}", envs.join(", "));
    /// # Ok::<(), rust_iac_config::ConfigError>(())
    /// ```
    pub fn environment_names(&self) -> Vec<String> {
        self.environments.iter().map(|e| e.name.clone()).collect()
    }
}

/// Project-level metadata
#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
pub struct ProjectInfo {
    /// Name of the project
    pub name: String,

    /// Root directory of the workspace (relative to config file or absolute)
    #[serde(default = "default_workspace_root")]
    pub workspace_root: PathBuf,

    /// Optional description of the project
    #[serde(default)]
    pub description: Option<String>,
}

fn default_workspace_root() -> PathBuf {
    PathBuf::from(".")
}

/// Configuration for a deployment environment
#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
pub struct Environment {
    /// Name of the environment (e.g., "dev", "staging", "prod")
    pub name: String,

    /// Path to Kubernetes manifests directory for this environment
    pub manifests_path: PathBuf,

    /// Whether this environment requires Kustomize
    #[serde(default)]
    pub requires_kustomize: bool,

    /// Optional environment-specific description
    #[serde(default)]
    pub description: Option<String>,

    /// Optional custom validation rules for this environment
    #[serde(default)]
    pub required_files: Vec<String>,
}

impl Environment {
    /// Validate environment configuration
    fn validate(&self, workspace_root: &Path) -> Result<(), ConfigError> {
        // Validate environment name is not empty
        if self.name.trim().is_empty() {
            return Err(ConfigError::missing_field(
                "environment.name",
                "Each environment must have a non-empty name",
            ));
        }

        // Validate manifests path
        let manifests_full_path = workspace_root.join(&self.manifests_path);
        if !manifests_full_path.exists() {
            return Err(ConfigError::directory_not_found(
                manifests_full_path.clone(),
                format!(
                    "Create the manifests directory for the '{}' environment:\n  mkdir -p {}",
                    self.name,
                    manifests_full_path.display()
                ),
            ));
        }

        // If kustomize is required, check for kustomization.yaml
        if self.requires_kustomize {
            let kustomization_file = manifests_full_path.join("kustomization.yaml");
            if !kustomization_file.exists() {
                return Err(ConfigError::ValidationFailed(format!(
                    "Environment '{}' requires Kustomize but {} does not exist.\n\n\
                    Create a kustomization.yaml file:\n  \
                    cd {} && kustomize create --autodetect",
                    self.name,
                    kustomization_file.display(),
                    manifests_full_path.display()
                )));
            }
        }

        // Check required files
        for file in &self.required_files {
            let file_path = manifests_full_path.join(file);
            if !file_path.exists() {
                return Err(ConfigError::ValidationFailed(format!(
                    "Environment '{}' requires file '{}' but it does not exist at: {}",
                    self.name,
                    file,
                    file_path.display()
                )));
            }
        }

        Ok(())
    }
}

/// Validation rules to enforce on the configuration
#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
#[serde(default)]
pub struct ValidationRules {
    /// Whether to verify the project is in a git repository
    pub check_git_repo: bool,

    /// List of directories that must exist in the workspace
    pub required_directories: Vec<PathBuf>,

    /// List of files that must exist in the workspace
    pub required_files: Vec<PathBuf>,

    /// Whether to validate that manifests paths are accessible
    pub validate_manifests_paths: bool,
}

impl Default for ValidationRules {
    fn default() -> Self {
        Self {
            check_git_repo: false,
            required_directories: Vec::new(),
            required_files: Vec::new(),
            validate_manifests_paths: true,
        }
    }
}

