//! Error types for IaC configuration and validation

use std::path::PathBuf;
use thiserror::Error;

/// Errors that can occur when loading, parsing, or validating IaC configuration
#[derive(Error, Debug)]
pub enum ConfigError {
    /// Configuration file was not found at the specified path
    #[error(
        "Configuration file not found: {0}\n\nCreate an IaC configuration file at this location. See the crate documentation for the expected format."
    )]
    FileNotFound(PathBuf),

    /// Failed to read the configuration file
    #[error("Failed to read configuration file {path}: {source}")]
    FileReadError {
        /// Path to the file that couldn't be read
        path: PathBuf,
        /// The underlying I/O error
        source: std::io::Error,
    },

    /// Configuration file contains invalid YAML
    #[error(
        "Invalid YAML in configuration file: {0}\n\nCheck the syntax of your configuration file. Common issues:\n- Indentation must use spaces, not tabs\n- String values with special characters should be quoted\n- List items must start with '-'"
    )]
    InvalidYaml(String),

    /// Required field is missing from configuration
    #[error("Missing required field in configuration: {field}\n\n{hint}")]
    MissingField {
        /// Name of the missing field
        field: String,
        /// Hint about what should be provided
        hint: String,
    },

    /// Invalid value provided for a configuration field
    #[error("Invalid value for field '{field}': {value}\n\n{hint}")]
    InvalidValue {
        /// Name of the field with invalid value
        field: String,
        /// The invalid value
        value: String,
        /// Hint about valid values
        hint: String,
    },

    /// Required directory does not exist
    #[error("Required directory not found: {path}\n\n{hint}")]
    DirectoryNotFound {
        /// Path to the missing directory
        path: PathBuf,
        /// Hint about what should be done
        hint: String,
    },

    /// Environment name not found in configuration
    #[error(
        "Environment '{0}' not found in configuration\n\nAvailable environments: {1}\n\nAdd this environment to your configuration file or use one of the available environments."
    )]
    EnvironmentNotFound(String, String),

    /// Duplicate environment names in configuration
    #[error(
        "Duplicate environment name in configuration: '{0}'\n\nEach environment must have a unique name."
    )]
    DuplicateEnvironment(String),

    /// Not in a git repository when git validation is enabled
    #[error(
        "Not in a git repository\n\nThis project requires git for version tracking. Initialize a git repository with:\n  git init"
    )]
    NotGitRepository,

    /// Validation error with custom message
    #[error("Validation failed: {0}")]
    ValidationFailed(String),

    /// Generic I/O error
    #[error("I/O error: {0}")]
    Io(#[from] std::io::Error),
}

impl ConfigError {
    /// Create a MissingField error with a helpful hint
    pub fn missing_field(field: impl Into<String>, hint: impl Into<String>) -> Self {
        ConfigError::MissingField { field: field.into(), hint: hint.into() }
    }

    /// Create an InvalidValue error with a helpful hint
    pub fn invalid_value(
        field: impl Into<String>,
        value: impl Into<String>,
        hint: impl Into<String>,
    ) -> Self {
        ConfigError::InvalidValue { field: field.into(), value: value.into(), hint: hint.into() }
    }

    /// Create a DirectoryNotFound error with a helpful hint
    pub fn directory_not_found(path: PathBuf, hint: impl Into<String>) -> Self {
        ConfigError::DirectoryNotFound { path, hint: hint.into() }
    }

    /// Create a FileReadError with context
    pub fn file_read_error(path: PathBuf, source: std::io::Error) -> Self {
        ConfigError::FileReadError { path, source }
    }
}

//! # rust_iac_config
//!
//! Generic YAML-based infrastructure configuration library for Rust IaC projects.
//!
//! This crate provides a simple, reusable configuration framework for defining and validating
//! infrastructure layouts. It is designed to be project-agnostic and makes no assumptions about
//! governance structure, acceptance criteria, or tooling beyond what is explicitly configured
//! in your YAML file.
//!
//! ## Overview
//!
//! `rust_iac_config` helps you:
//! - Define and validate project-specific IaC configurations
//! - Ensure required directories and files exist before deployment
//! - Provide clear, actionable error messages for misconfigurations
//! - Maintain a minimal, well-documented public API
//!
//! ## Quick Start
//!
//! Create a configuration file (e.g., `iac-config.yaml`):
//!
//! ```yaml
//! project:
//!   name: my-rust-project
//!   workspace_root: .
//!
//! environments:
//!   - name: dev
//!     manifests_path: infra/k8s/dev
//!     requires_kustomize: false
//!   - name: staging
//!     manifests_path: infra/k8s/staging
//!     requires_kustomize: true
//!   - name: prod
//!     manifests_path: infra/k8s/prod
//!     requires_kustomize: true
//!
//! validation:
//!   check_git_repo: true
//!   required_directories:
//!     - specs
//!     - infra
//! ```
//!
//! Load and validate the configuration in your code:
//!
//! ```rust,ignore
//! use rust_iac_config::{IaCConfig, ConfigError};
//! use std::path::Path;
//!
//! fn main() -> Result<(), ConfigError> {
//!     let config = IaCConfig::from_file(Path::new("iac-config.yaml"))?;
//!
//!     // Access validated configuration
//!     println!("Project: {}", config.project.name);
//!
//!     // Find an environment
//!     let dev_env = config.find_environment("dev")
//!         .ok_or_else(|| ConfigError::EnvironmentNotFound(
//!             "dev".to_string(),
//!             "Environment not found in configuration".to_string()
//!         ))?;
//!
//!     println!("Dev manifests: {}", dev_env.manifests_path.display());
//!
//!     Ok(())
//! }
//! ```
//!
//! ## Error Handling
//!
//! All errors are represented by the [`ConfigError`] type, which provides:
//! - Structured error variants for different failure modes
//! - Human-readable error messages
//! - Context about what went wrong and how to fix it
//!
//! ```rust,no_run
//! use rust_iac_config::{IaCConfig, ConfigError};
//! use std::path::Path;
//!
//! match IaCConfig::from_file(Path::new("config.yaml")) {
//!     Ok(config) => println!("Config loaded successfully"),
//!     Err(ConfigError::FileNotFound(path)) => {
//!         eprintln!("Config file not found: {}", path.display());
//!         eprintln!("Create a config file at that location.");
//!     }
//!     Err(ConfigError::InvalidYaml(msg)) => {
//!         eprintln!("Invalid YAML: {}", msg);
//!     }
//!     Err(e) => eprintln!("Error: {}", e),
//! }
//! ```
//!
//! ## Design Philosophy
//!
//! This library follows these principles:
//! - **No panics**: All error conditions return `Result` types
//! - **Validation first**: Configuration is validated on load, not at use time
//! - **Clear errors**: Error messages explain what's wrong and suggest fixes
//! - **Minimal API**: Small public surface area that's easy to understand
//! - **No assumptions**: Works with any project structure defined in config

mod config;
mod error;
mod validation;

pub use config::{Environment, IaCConfig, ProjectInfo, ValidationRules};
pub use error::ConfigError;

/// Result type alias for this crate
pub type Result<T> = std::result::Result<T, ConfigError>;

//! Validation logic for IaC configurations

use crate::config::IaCConfig;
use crate::error::ConfigError;
use std::path::Path;
use std::process::Command;

/// Validate the entire configuration based on validation rules
pub(crate) fn validate_config(config: &IaCConfig) -> Result<(), ConfigError> {
    let workspace_root = &config.project.workspace_root;

    // Check if git repository is required
    if config.validation.check_git_repo {
        validate_git_repository(workspace_root)?;
    }

    // Check required directories
    for dir in &config.validation.required_directories {
        let dir_path = workspace_root.join(dir);
        if !dir_path.exists() || !dir_path.is_dir() {
            return Err(ConfigError::directory_not_found(
                dir_path.clone(),
                format!(
                    "This directory is required by the project configuration.\n\
                    Create it with:\n  mkdir -p {}",
                    dir_path.display()
                ),
            ));
        }
    }

    // Check required files
    for file in &config.validation.required_files {
        let file_path = workspace_root.join(file);
        if !file_path.exists() || !file_path.is_file() {
            return Err(ConfigError::ValidationFailed(format!(
                "Required file not found: {}\n\n\
                This file is required by the project configuration.",
                file_path.display()
            )));
        }
    }

    Ok(())
}

/// Validate that the workspace is in a git repository
fn validate_git_repository(workspace_root: &Path) -> Result<(), ConfigError> {
    let output = Command::new("git")
        .arg("rev-parse")
        .arg("--is-inside-work-tree")
        .current_dir(workspace_root)
        .output();

    match output {
        Ok(output) if output.status.success() => Ok(()),
        _ => Err(ConfigError::NotGitRepository),
    }
}

