                adrs: vec!["ADR-0006".to_string()],
                extra: BTreeMap::new(),
            },
        };

        let json = serde_json::to_string(&hint).unwrap();
        let parsed: serde_json::Value = serde_json::from_str(&json).unwrap();

        // Verify all required fields are present
        assert!(parsed.get("id").is_some(), "Missing 'id' field");
        assert!(parsed.get("kind").is_some(), "Missing 'kind' field");
        assert!(parsed.get("priority").is_some(), "Missing 'priority' field");
        assert!(parsed.get("status").is_some(), "Missing 'status' field");
        assert!(parsed.get("reason").is_some(), "Missing 'reason' field");
        assert!(parsed.get("target").is_some(), "Missing 'target' field");
        assert!(parsed.get("tags").is_some(), "Missing 'tags' field");
        assert!(parsed.get("links").is_some(), "Missing 'links' field");

        // Verify reason has code and details
        let reason = parsed.get("reason").unwrap();
        assert!(reason.get("code").is_some(), "reason missing 'code'");
        assert!(reason.get("details").is_some(), "reason missing 'details'");

        // Verify target has type and id
        let target = parsed.get("target").unwrap();
        assert!(target.get("type").is_some(), "target missing 'type'");
        assert!(target.get("id").is_some(), "target missing 'id'");

        // Verify links structure
        let links = parsed.get("links").unwrap();
        assert!(links.get("spec").is_some(), "links missing 'spec'");
        assert!(links.get("task").is_some(), "links missing 'task'");
        assert!(links.get("docs").is_some(), "links missing 'docs'");
        assert!(links.get("adrs").is_some(), "links missing 'adrs'");

        // Verify enum serialization format (snake_case)
        assert_eq!(parsed.get("kind").unwrap(), "task");
        assert_eq!(parsed.get("priority").unwrap(), "high");
        assert_eq!(parsed.get("status").unwrap(), "open");
        assert_eq!(target.get("type").unwrap(), "task");
    }
}

//! K8s Infrastructure-as-Code alignment tests
//!
//! This module validates that Kubernetes manifests align with the
//! config schema and environment definitions.

#[cfg(test)]
mod tests {
    use crate::validate_config;
    use serde_yaml::Value;
    use std::collections::HashSet;
    use std::fs;
    use std::path::PathBuf;

    fn workspace_root() -> PathBuf {
        let manifest_dir = PathBuf::from(env!("CARGO_MANIFEST_DIR"));
        manifest_dir
            .parent()
            .and_then(|p| p.parent())
            .expect("workspace root should be two levels above spec-runtime")
            .to_path_buf()
    }

    /// AC-TPL-IAC-K8S-ALIGN: Kubernetes manifests under infra/k8s align with config_schema.yaml
    #[test]
    fn iac_k8s_aligns_with_config() {
        let root = workspace_root();
        let k8s_base = root.join("infra/k8s/dev");

        // Load K8s manifests
        let deployment = load_k8s_manifest(&k8s_base.join("deployment.yaml"));
        let service = load_k8s_manifest(&k8s_base.join("service.yaml"));
        let configmap = load_k8s_manifest(&k8s_base.join("configmap.yaml"));

        // Load and validate config schema
        let config = validate_config(
            &root.join("specs/config_schema.yaml"),
            &root.join("config/local.yaml"),
        )
        .expect("config/local.yaml should validate against specs/config_schema.yaml");

        // Load config schema to get expected settings/secrets keys
        let schema_content = fs::read_to_string(root.join("specs/config_schema.yaml"))
            .expect("Failed to read config_schema.yaml");
        let schema: Value =
            serde_yaml::from_str(&schema_content).expect("Failed to parse config_schema.yaml");

        let expected_settings = extract_config_keys(&schema, "settings");
        let expected_secrets = extract_config_keys(&schema, "secrets");

        // Validate Deployment
        validate_deployment_ports(&deployment, config.http_port);
        validate_deployment_configmap_ref(&deployment, "app-config");
        validate_deployment_secret_ref(&deployment, "app-secrets");

        // Validate Service
        validate_service_ports(&service, config.http_port);

        // Validate ConfigMap alignment with config schema
        validate_configmap_keys(&configmap, &expected_settings, &expected_secrets);

        println!("✓ K8s manifests align with config schema");
    }

    fn load_k8s_manifest(path: &PathBuf) -> Value {
        let contents = fs::read_to_string(path)
            .unwrap_or_else(|_| panic!("Failed to read K8s manifest at {}", path.display()));
        serde_yaml::from_str(&contents)
            .unwrap_or_else(|_| panic!("Failed to parse K8s manifest at {}", path.display()))
    }

    fn extract_config_keys(schema: &Value, section: &str) -> HashSet<String> {
        schema
            .get(section)
            .and_then(Value::as_sequence)
            .map(|items| {
                items
                    .iter()
                    .filter_map(|item| item.get("key").and_then(Value::as_str).map(String::from))
                    .collect()
            })
            .unwrap_or_default()
    }

    fn validate_deployment_ports(deployment: &Value, expected_http_port: u16) {
        let containers = deployment
            .get("spec")
            .and_then(|s| s.get("template"))
            .and_then(|t| t.get("spec"))
            .and_then(|s| s.get("containers"))
            .and_then(Value::as_sequence)
            .expect("Deployment should have containers");

        let mut found_http_port = false;
        for container in containers {
            if let Some(ports) = container.get("ports").and_then(Value::as_sequence) {
                for port in ports {
                    if let Some(name) = port.get("name").and_then(Value::as_str)
                        && name == "http"
                    {
                        let container_port = port
                            .get("containerPort")
                            .and_then(Value::as_u64)
                            .expect("http port should have containerPort");
                        assert_eq!(
                            container_port, expected_http_port as u64,
                            "Deployment containerPort should match config_schema.yaml http.port ({})",
                            expected_http_port
                        );
                        found_http_port = true;
                    }
                }
            }
        }
        assert!(found_http_port, "Deployment should expose http port matching config schema");
    }

    fn validate_deployment_configmap_ref(deployment: &Value, expected_name: &str) {
        let env_from = deployment
            .get("spec")
            .and_then(|s| s.get("template"))
            .and_then(|t| t.get("spec"))
            .and_then(|s| s.get("containers"))
            .and_then(Value::as_sequence)
            .and_then(|containers| containers.first())
            .and_then(|c| c.get("envFrom"))
            .and_then(Value::as_sequence)
            .expect("Deployment should have envFrom");

        let has_configmap_ref = env_from.iter().any(|ref_obj| {
            ref_obj.get("configMapRef").and_then(|cm| cm.get("name")).and_then(Value::as_str)
                == Some(expected_name)
        });

        assert!(has_configmap_ref, "Deployment should reference ConfigMap '{}'", expected_name);
    }

    fn validate_deployment_secret_ref(deployment: &Value, expected_name: &str) {
        let env_from = deployment
            .get("spec")
            .and_then(|s| s.get("template"))
            .and_then(|t| t.get("spec"))
            .and_then(|s| s.get("containers"))
            .and_then(Value::as_sequence)
            .and_then(|containers| containers.first())
            .and_then(|c| c.get("envFrom"))
            .and_then(Value::as_sequence)
            .expect("Deployment should have envFrom");

        let has_secret_ref = env_from.iter().any(|ref_obj| {
            ref_obj.get("secretRef").and_then(|s| s.get("name")).and_then(Value::as_str)
                == Some(expected_name)
        });

        assert!(has_secret_ref, "Deployment should reference Secret '{}'", expected_name);
    }

    fn validate_service_ports(service: &Value, expected_http_port: u16) {
        let ports = service
            .get("spec")
            .and_then(|s| s.get("ports"))
            .and_then(Value::as_sequence)
            .expect("Service should have ports");

        let has_http_port = ports.iter().any(|port| {
            port.get("name").and_then(Value::as_str) == Some("http")
                && port.get("targetPort").and_then(Value::as_str) == Some("http")
        });

        assert!(
            has_http_port,
            "Service should map to http port (targetPort: http) which ultimately maps to containerPort {}",
            expected_http_port
        );
    }

    fn validate_configmap_keys(
        configmap: &Value,
        _expected_settings: &HashSet<String>,
        expected_secrets: &HashSet<String>,
    ) {
        let data =
            configmap.get("data").and_then(Value::as_mapping).expect("ConfigMap should have data");

        let configmap_keys: HashSet<String> =
            data.keys().filter_map(|k| k.as_str().map(String::from)).collect();

        // ConfigMap should not contain secret keys
        for secret_key in expected_secrets {
            // Convert dotted keys to env var format (e.g., db.url -> DB_URL or DATABASE_URL)
            let env_variants = key_to_env_variants(secret_key);
            for variant in &env_variants {
                assert!(
                    !configmap_keys.contains(variant),
                    "ConfigMap should not contain secret key '{}' (or variant '{}')",
                    secret_key,
                    variant
                );
            }
        }

        // We don't enforce that ALL settings are in ConfigMap since some may be set via other means,
        // but we do verify the PORT key is present and matches config schema
        assert!(
            configmap_keys.contains("PORT"),
            "ConfigMap should contain PORT env var for http.port setting"
        );

        let port_value = data
            .get(Value::String("PORT".to_string()))
            .and_then(Value::as_str)
            .expect("PORT should be a string");

        // Note: We can't directly validate the port value here without loading config,
        // but we validate its presence. The integration comes from validate_deployment_ports.
        assert!(!port_value.is_empty(), "PORT value should not be empty in ConfigMap");
    }

    fn key_to_env_variants(key: &str) -> Vec<String> {
        // Generate common env var naming variants
        let upper = key.to_uppercase().replace('.', "_");
        vec![
            upper.clone(),
            // Also handle common mappings like db.url -> DATABASE_URL
            match key {
                "db.url" => "DATABASE_URL".to_string(),
                "auth.jwt_signing_key" => "JWT_SIGNING_KEY".to_string(),
                _ => upper,
            },
        ]
    }
}

//! Governance spec ledger (stories, requirements, acceptance criteria).
//!
//! This module defines the structure of `spec_ledger.yaml`, the core governance document
//! that maps user stories → requirements → acceptance criteria → tests.

use anyhow::{Context, Result};
use serde::{Deserialize, Serialize};
use std::path::Path;

/// Spec ledger containing all governance stories and requirements.
///
/// The root structure of `specs/spec_ledger.yaml`.
#[derive(Debug, Deserialize, Serialize, Clone)]
pub struct SpecLedger {
    /// Metadata about the spec ledger (version, last updated, description).
    pub metadata: Metadata,
    /// List of all user stories in the ledger.
    pub stories: Vec<Story>,
}

/// Metadata for the spec ledger.
#[derive(Debug, Deserialize, Serialize, Clone)]
pub struct Metadata {
    /// Schema version for spec_ledger.yaml.
    pub schema_version: String,
    /// Template version this ledger is compatible with.
    pub template_version: String,
    /// ISO 8601 timestamp of last update.
    pub last_updated: String,
    /// Human-readable description of this ledger.
    pub description: String,
}

/// A user story with associated requirements.
#[derive(Debug, Deserialize, Serialize, Clone)]
pub struct Story {
    /// Unique story ID (e.g., "US-TPL-001").
    pub id: String,
    /// Title of the story.
    pub title: String,
    /// List of requirements for this story.
    pub requirements: Vec<Requirement>,
}

/// A requirement with acceptance criteria.
#[derive(Debug, Deserialize, Serialize, Clone)]
pub struct Requirement {
    /// Unique requirement ID (e.g., "REQ-TPL-CONFIG").
    pub id: String,
    /// Title of the requirement.
    pub title: String,
    /// Optional tags for categorization.
    #[serde(default)]
    pub tags: Vec<String>,
    /// Whether this requirement must have at least one acceptance criterion (default: true).
    #[serde(default = "default_must_have_ac")]
    pub must_have_ac: bool,
    /// List of acceptance criteria for this requirement.
    pub acceptance_criteria: Vec<AcceptanceCriterion>,
}

fn default_must_have_ac() -> bool {
    true
}

/// Mapping from an AC to a test.
///
/// Describes how a test relates to an acceptance criterion.
#[derive(Debug, Deserialize, Serialize, Clone)]
pub struct TestMapping {
    /// Type of test (e.g., "bdd", "unit", "integration").
    #[serde(rename = "type")]
    pub test_type: String,
    /// Test tag or scenario identifier.
    pub tag: String,
    /// Optional file path where the test is defined.
    #[serde(skip_serializing_if = "Option::is_none")]
    pub file: Option<String>,
    /// Optional module path for the test.
    #[serde(skip_serializing_if = "Option::is_none")]
    #[serde(default)]
    pub module: Option<String>,
}

/// An acceptance criterion with test mappings.
#[derive(Debug, Deserialize, Serialize, Clone)]
pub struct AcceptanceCriterion {
    /// Unique AC ID (e.g., "AC-TPL-CONFIG-001").
    pub id: String,
    /// Description of what this AC validates.
    pub text: String,
    /// List of tests that cover this AC.
    #[serde(default)]
    pub tests: Vec<TestMapping>,
}

/// Load the spec ledger from a YAML file.
///
/// # Arguments
///
/// * `path` - Path to `spec_ledger.yaml`
///
/// # Returns
///
/// Returns a parsed [`SpecLedger`] instance.
///
/// # Errors
///
/// Returns an error if the file is missing, unreadable, or malformed YAML.
///
/// # Example
///
/// ```ignore
/// let ledger = load_spec_ledger(Path::new("specs/spec_ledger.yaml"))?;
/// println!("Loaded {} stories", ledger.stories.len());
/// ```
pub fn load_spec_ledger(path: &Path) -> Result<SpecLedger> {
    let content = std::fs::read_to_string(path)
        .with_context(|| format!("Failed to read spec ledger: {}", path.display()))?;

    serde_yaml::from_str(&content)
        .with_context(|| format!("Failed to parse spec ledger: {}", path.display()))
}

//! Spec runtime library for the Rust-as-Spec platform.
//!
//! This library provides runtime support for loading, validating, and operating on
//! governance specifications, configuration schemas, and development flows. It serves
//! as the core runtime for spec-driven development workflows.
//!
//! # Main Components
//!
//! - **Configuration**: Schema-driven config validation ([`config`])
//! - **Governance**: Spec ledger, stories, requirements, ACs ([`ledger`])
//! - **Developer Experience**: Flow and command definitions ([`devex`])
//! - **Documentation**: Doc inventory and indexing ([`docs`])
//! - **Governance Graph**: Story → REQ → AC → tests → docs relationships ([`graph`])
//! - **Agent Hints**: AC coverage and task prioritization ([`hints`])
//! - **Tasks**: Work item tracking and sequencing ([`tasks`])
//! - **Schema**: Platform API schemas and endpoints ([`schema`])
//!
//! # Example
//!
//! ```ignore
//! use spec_runtime::{load_all_specs, validate_config};
//! use std::path::Path;
//!
//! let root = Path::new("/workspace");
//! let specs = load_all_specs(root)?;
//! let config = validate_config(
//!     &root.join("specs/config_schema.yaml"),
//!     &root.join("config/local.yaml")
//! )?;
//! ```

use anyhow::Result;
use std::path::Path;

/// Configuration schema validation and runtime config types.
pub mod config;
/// Developer experience flows and xtask command specs.
pub mod devex;
/// Documentation inventory and indexing.
pub mod docs;
/// Governance graph builder (stories → REQs → ACs → tests → docs).
pub mod graph;
/// Agent hint engine for AC coverage and task prioritization.
pub mod hints;
/// Kubernetes IaC configuration support.
pub mod k8s_iac;
/// Spec ledger (stories, requirements, acceptance criteria).
pub mod ledger;
/// Local Docker configuration support.
pub mod local_docker;
/// Platform API schemas and endpoint metadata.
pub mod schema;
/// Service metadata loader.
pub mod service_metadata;
/// Task management and sequencing.
pub mod tasks;

pub use config::{ValidatedConfig, validate_config};
pub use devex::{DevExFlows, load_devex_flows};
pub use docs::{DocEntry, DocIndex, load_doc_index};
pub use graph::{Edge, Graph, Node, build_graph};
pub use hints::{
    AcCoverage, AcCoverageIndex, AcExecutionStatus, Hint, HintEngine, HintFilter, HintKind,
    HintLinks, HintPriority, HintReason, HintStatus, HintTarget,
};
pub use ledger::{AcceptanceCriterion, Requirement, SpecLedger, Story, load_spec_ledger};
