/// Task graph structures for dependency visualization
#[derive(Debug, Serialize, Deserialize)]
pub struct TaskGraph {
    pub nodes: Vec<TaskNode>,
    pub edges: Vec<TaskEdge>,
    pub blocking_relationships: Vec<BlockingRelationship>,
}

#[derive(Debug, Serialize, Deserialize, Clone)]
pub struct TaskNode {
    pub id: String,
    pub title: String,
    pub status: String,
    pub requirement: String,
    pub owner: Option<String>,
    pub labels: Vec<String>,
}

#[derive(Debug, Serialize, Deserialize)]
pub struct TaskEdge {
    pub from: String,      // Task that depends
    pub to: String,        // Task being depended on
    pub edge_type: String, // "depends_on"
}

#[derive(Debug, Serialize, Deserialize)]
pub struct BlockingRelationship {
    pub blocked_task: String,
    pub blocking_tasks: Vec<String>,
    pub reason: String,
}

/// Build a task dependency graph from tasks spec
pub fn build_task_graph(tasks_spec: &TasksSpec) -> TaskGraph {
    let mut nodes = Vec::new();
    let mut edges = Vec::new();
    let mut blocking = Vec::new();

    // Build nodes
    for task in &tasks_spec.tasks {
        nodes.push(TaskNode {
            id: task.id.clone(),
            title: task.title.clone(),
            status: task.status.clone(),
            requirement: task.requirement.clone(),
            owner: task.owner.clone(),
            labels: task.labels.clone(),
        });
    }

    // Build edges and identify blocking relationships
    let task_status_map: HashMap<String, String> =
        tasks_spec.tasks.iter().map(|t| (t.id.clone(), t.status.clone())).collect();

    for task in &tasks_spec.tasks {
        let mut incomplete_dependencies = Vec::new();

        for dep_id in &task.depends_on {
            edges.push(TaskEdge {
                from: task.id.clone(),
                to: dep_id.clone(),
                edge_type: "depends_on".to_string(),
            });

            // Check if dependency is blocking (not Done)
            if let Some(dep_status) = task_status_map.get(dep_id) {
                let normalized_status = normalize_status_for_blocking(dep_status);
                if normalized_status != "Done" {
                    incomplete_dependencies.push(dep_id.clone());
                }
            } else {
                // Dependency task doesn't exist - that's a problem
                incomplete_dependencies.push(dep_id.clone());
            }
        }

        // If this task has incomplete dependencies, record blocking relationship
        if !incomplete_dependencies.is_empty() && task.status != "done" && task.status != "Done" {
            blocking.push(BlockingRelationship {
                blocked_task: task.id.clone(),
                blocking_tasks: incomplete_dependencies.clone(),
                reason: format!(
                    "Task '{}' is blocked by {} incomplete dependencies",
                    task.id,
                    incomplete_dependencies.len()
                ),
            });
        }
    }

    TaskGraph { nodes, edges, blocking_relationships: blocking }
}

/// Generate Mermaid diagram for task graph
pub fn generate_mermaid_diagram(graph: &TaskGraph) -> String {
    let mut output = String::new();
    output.push_str("graph TD\n");

    // Add nodes with status coloring
    for node in &graph.nodes {
        let label = format!("{}[{}]", node.id, escape_mermaid_label(&node.title));
        output.push_str(&format!("  {}:::{}\n", label, status_to_class(&node.status)));
    }

    // Add edges
    for edge in &graph.edges {
        output.push_str(&format!("  {} -->|depends on| {}\n", edge.from, edge.to));
    }

    // Add style classes
    output.push_str("\n  classDef done fill:#90EE90,stroke:#333,stroke-width:2px\n");
    output.push_str("  classDef inprogress fill:#FFD700,stroke:#333,stroke-width:2px\n");
    output.push_str("  classDef review fill:#87CEEB,stroke:#333,stroke-width:2px\n");
    output.push_str("  classDef todo fill:#FFB6C1,stroke:#333,stroke-width:2px\n");

    output
}

fn normalize_status_for_blocking(status: &str) -> String {
    let key = status.trim().to_ascii_lowercase().replace([' ', '-'], "_");
    match key.as_str() {
        "todo" | "open" => "Todo".to_string(),
        "inprogress" | "in_progress" => "InProgress".to_string(),
        "review" => "Review".to_string(),
        "done" | "closed" => "Done".to_string(),
        _ => "Todo".to_string(),
    }
}

fn status_to_class(status: &str) -> String {
    match normalize_status_for_blocking(status).as_str() {
        "Done" => "done",
        "InProgress" => "inprogress",
        "Review" => "review",
        _ => "todo",
    }
    .to_string()
}

fn escape_mermaid_label(label: &str) -> String {
    label
        .replace('"', "'")
        .replace('[', "(")
        .replace(']', ")")
        .chars()
        .take(50) // Limit label length
        .collect()
}

/// Initialize tracing with env-based log filtering and optional OTLP export
///
/// Respects `RUST_LOG` environment variable for filtering.
/// Default level: INFO
///
/// ## OTLP Export (Optional)
///
/// When the `otlp` feature is enabled and `OTLP_ENDPOINT` is set, traces will be
/// exported via OTLP using gRPC (tonic). If OTLP initialization fails, the system
/// falls back to console-only tracing with a warning.
///
/// Environment Variables:
/// - `RUST_LOG`: Logging filter (e.g., `debug`, `app_http=trace`)
/// - `OTLP_ENDPOINT`: OTLP collector endpoint (e.g., `http://localhost:4317`)
///
/// Examples:
/// ```ignore
/// RUST_LOG=debug cargo run
/// RUST_LOG=app_http=trace,business_core=debug cargo run
/// OTLP_ENDPOINT=http://localhost:4317 cargo run --features telemetry/otlp
/// ```
pub fn init_tracing(service_name: &str) {
    use tracing_subscriber::EnvFilter;

    let env_filter = EnvFilter::try_from_default_env().unwrap_or_else(|_| EnvFilter::new("info"));

    #[cfg(feature = "otlp")]
    {
        if let Ok(endpoint) = std::env::var("OTLP_ENDPOINT")
            && !endpoint.is_empty()
        {
            match try_init_otlp(service_name, &endpoint, env_filter.clone()) {
                Ok(()) => {
                    tracing::info!(
                        service = service_name,
                        endpoint = %endpoint,
                        "Initialized OTLP tracing"
                    );
                    return;
                }
                Err(e) => {
                    eprintln!(
                        "Failed to initialize OTLP exporter: {e}, falling back to console tracing"
                    );
                }
            }
        }
    }

    // Default console tracing (also used as fallback if OTLP fails)
    let _ = tracing_subscriber::fmt().with_env_filter(env_filter).try_init();

    tracing::info!(service = service_name, "Initialized console tracing");
}

#[cfg(feature = "otlp")]
fn try_init_otlp(
    service_name: &str,
    endpoint: &str,
    env_filter: tracing_subscriber::EnvFilter,
) -> Result<(), Box<dyn std::error::Error>> {
    use opentelemetry::global;
    use opentelemetry_otlp::{SpanExporter, WithExportConfig};
    use opentelemetry_sdk::{Resource, trace::SdkTracerProvider};
    use tracing_subscriber::layer::SubscriberExt;

    // Build OTLP exporter using gRPC (tonic)
    let exporter = SpanExporter::builder().with_tonic().with_endpoint(endpoint).build()?;

    // Create tracer provider with resource metadata
    let provider = SdkTracerProvider::builder()
        .with_batch_exporter(exporter)
        .with_resource(Resource::builder().with_service_name(service_name.to_string()).build())
        .build();

    // Set global tracer provider
    global::set_tracer_provider(provider);

    // Create tracing-opentelemetry layer
    let tracer = global::tracer(service_name.to_string());
    let telemetry_layer = tracing_opentelemetry::layer().with_tracer(tracer);

    // Combine OTLP + console layers
    let subscriber = tracing_subscriber::registry()
        .with(env_filter)
        .with(telemetry_layer)
        .with(tracing_subscriber::fmt::layer());

    tracing::subscriber::set_global_default(subscriber)?;

    Ok(())
}

/// Initialize tracing for tests
///
/// Use this in test setup to get structured logs during test execution.
#[cfg(test)]
pub fn init_test() {
    let _ = tracing_subscriber::fmt()
        .with_test_writer()
        .with_max_level(tracing::Level::DEBUG)
        .try_init();
}

use anyhow::Result;
use colored::Colorize;
use std::collections::{BTreeMap, HashMap};
use std::path::Path;
use std::path::PathBuf;

use super::ac_parsing::{AcStatus, parse_cucumber_json, parse_features, parse_junit, parse_ledger};

pub fn run(args: AcCoverageArgs) -> Result<()> {
    println!("{}", "📊 Computing AC coverage...".blue().bold());
    println!();

    // Parse ledger
    let ledger_path = Path::new("specs/spec_ledger.yaml");
    if !ledger_path.exists() {
        anyhow::bail!("spec_ledger.yaml not found at {}", ledger_path.display());
    }

    let (all_acs, acs_by_req) = parse_ledger(ledger_path)?;

    // Parse scenarios from features
    let scenarios = parse_features(&args.features_dir)?;

    // Parse test results
    let ac_results = if args.json_report.exists() {
        parse_cucumber_json(&args.json_report).or_else(|_| {
            // Fallback if JSON doesn't exist or is invalid
            if args.junit.exists() {
                parse_junit(&args.junit, &scenarios)
            } else {
                Ok(HashMap::new())
            }
        })?
    } else if args.junit.exists() {
        parse_junit(&args.junit, &scenarios)?
    } else {
        HashMap::new()
    };

    // Determine AC statuses
    let mut ac_statuses: HashMap<String, AcStatus> = HashMap::new();
    for ac_id in all_acs.keys() {
        if let Some(status) = ac_results.get(ac_id) {
            ac_statuses.insert(ac_id.clone(), status.clone());
        } else {
            ac_statuses.insert(ac_id.clone(), AcStatus::Unknown);
        }
    }

    // Generate report
    print_coverage_report(&all_acs, &acs_by_req, &ac_statuses)?;

    Ok(())
}

fn print_coverage_report(
    all_acs: &HashMap<String, String>,
    _acs_by_req: &BTreeMap<String, Vec<String>>,
    ac_statuses: &HashMap<String, AcStatus>,
) -> Result<()> {
    let passing = ac_statuses.values().filter(|s| **s == AcStatus::Pass).count();
    let failing = ac_statuses.values().filter(|s| **s == AcStatus::Fail).count();
    let unknown = ac_statuses.values().filter(|s| **s == AcStatus::Unknown).count();

    println!("{} AC Coverage Summary", "📋".bold());
    println!("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
    println!();
    println!("  {} {} passing", "✓".green(), passing);
    println!("  {} {} failing", "✗".red(), failing);
    println!("  {} {} unknown (no BDD scenarios)", "?".yellow(), unknown);
    println!();

    // Group unknowns by requirement
    let mut unknowns_by_req: BTreeMap<String, Vec<String>> = BTreeMap::new();
    for (ac_id, status) in ac_statuses {
        if *status == AcStatus::Unknown
            && let Some(req_id) = all_acs.get(ac_id)
        {
            unknowns_by_req.entry(req_id.clone()).or_default().push(ac_id.clone());
        }
    }

    if !unknowns_by_req.is_empty() {
        println!("{} Unknown ACs (Need BDD scenarios)", "📍".cyan().bold());
        println!("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
        println!();

        for (req_id, mut ac_ids) in unknowns_by_req {
            ac_ids.sort();
            let ac_list = ac_ids.join(", ");
            println!("  {}: {}", req_id.cyan(), ac_list);
        }
        println!();
    }

    // Suggest next steps
    if unknown > 0 {
        println!("{} Suggested Next Steps", "🎯".bold());
        println!("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
        println!();

        // Pick first unknown AC for example
        if let Some((ac_id, _)) = ac_statuses.iter().find(|(_, s)| **s == AcStatus::Unknown) {
            println!("  1. Generate scenario stub for {}:", ac_id.cyan());
            println!(
                "     {} {} {}",
                "$".dimmed(),
                "cargo xtask ac-suggest-scenarios".cyan(),
                ac_id
            );
            println!();
        }

        println!("  2. Edit specs/features/your_feature.feature:");
        println!("     {} {}", "$".dimmed(), "vim specs/features/your_feature.feature".cyan());
        println!();
        println!("  3. Run BDD tests:");
        println!("     {} {}", "$".dimmed(), "cargo xtask bdd".cyan());
        println!();
        println!("  4. Check coverage again:");
        println!("     {} {}", "$".dimmed(), "cargo xtask ac-coverage".cyan());
    } else {
        println!("{} {} All ACs have BDD coverage!", "🎉".bold(), "✓".green());
    }

    println!();

    Ok(())
}

