// Public Types
// ============================================================================

#[derive(Debug, Clone, PartialEq, serde::Serialize)]
#[serde(rename_all = "lowercase")]
pub enum AcStatus {
    Pass,
    Fail,
    Unknown,
}

#[derive(Debug, Clone)]
pub struct Scenario {
    pub name: String,
    pub ac_id: String,
    pub file: String,
}

// Type aliases to reduce complexity
pub type AcsByReq = BTreeMap<String, Vec<String>>;
pub type AcToReqMap = HashMap<String, String>;

