use anyhow::{Context, Result};
use colored::Colorize;
use spec_runtime::{SpecLedger, load_spec_ledger};
use std::path::PathBuf;

pub fn run(ac_id: &str) -> Result<()> {
    let root =
        PathBuf::from(env!("CARGO_MANIFEST_DIR")).parent().unwrap().parent().unwrap().to_path_buf();

    let ledger_path = root.join("specs/spec_ledger.yaml");
    let ledger: SpecLedger =
        load_spec_ledger(&ledger_path).context("Failed to load spec_ledger.yaml")?;

    // Find the AC in the ledger
    let mut found_ac = None;
    let mut req_id = String::new();
    let mut story_id = String::new();

    for story in &ledger.stories {
        for req in &story.requirements {
            for ac in &req.acceptance_criteria {
                if ac.id == ac_id {
                    found_ac = Some(ac.clone());
                    req_id = req.id.clone();
                    story_id = story.id.clone();
                    break;
                }
            }
            if found_ac.is_some() {
                break;
            }
        }
        if found_ac.is_some() {
            break;
        }
    }

    let ac = found_ac.context(format!("AC {} not found in spec_ledger.yaml", ac_id))?;

    // Display AC information
    println!("{}", "=".repeat(80).bright_blue());
    println!("{} {}", "Acceptance Criterion:".bright_blue().bold(), ac_id.bright_white().bold());
    println!("{}", "=".repeat(80).bright_blue());
    println!();
    println!("{} {}", "Story:".bright_cyan(), story_id);
    println!("{} {}", "Requirement:".bright_cyan(), req_id);
    println!("{} {}", "Text:".bright_cyan(), ac.text);
    println!();

    if ac.tests.is_empty() {
        println!("{}", "⚠ No tests mapped to this AC".yellow().bold());
        return Ok(());
    }

    println!("{}", "Mapped Tests:".bright_green().bold());
    println!("{}", "-".repeat(80).bright_blue());
    println!();

    for (idx, test_mapping) in ac.tests.iter().enumerate() {
        let test_num = format!("[{}]", idx + 1);
        println!(
            "{} {} {}",
            test_num.bright_yellow().bold(),
            "Type:".bright_cyan(),
            test_mapping.test_type
        );
        println!("    {} {}", "Tag:".bright_cyan(), test_mapping.tag);

        if let Some(file) = &test_mapping.file {
            println!("    {} {}", "File:".bright_cyan(), file.bright_white());
        }

        if let Some(module) = &test_mapping.module {
            println!("    {} {}", "Module:".bright_cyan(), module.bright_white());
        }

        println!();
    }

    // Provide actionable commands
    println!("{}", "Run Tests:".bright_green().bold());
    println!("{}", "-".repeat(80).bright_blue());
    println!();

    for test_mapping in &ac.tests {
        match test_mapping.test_type.as_str() {
            "bdd" | "integration" => {
                let tag = &test_mapping.tag;
                let clean_tag = tag.trim_start_matches('@');
                println!(
                    "  {} {}",
                    "BDD/Integration:".bright_cyan(),
                    format!("cargo xtask test-ac {}", ac_id).bright_white()
                );
                println!(
                    "  {} {}",
                    "Direct:".bright_cyan(),
                    format!("CUCUMBER_TAG_EXPRESSION='@{}' cargo test -p acceptance", clean_tag)
                        .bright_white()
                );
            }
            "unit" => {
                if let Some(module) = &test_mapping.module {
                    println!(
                        "  {} {}",
                        "Unit test:".bright_cyan(),
                        format!("cargo test -p spec-runtime {}", module).bright_white()
                    );
                }
            }
            _ => {
                println!("  {} {}", "Unknown type:".yellow(), test_mapping.test_type);
            }
        }
        println!();
    }

    Ok(())
}

use anyhow::{Context, Result};
use colored::Colorize;
use serde::Deserialize;
use std::collections::HashSet;
use std::fs;
use std::path::{Path, PathBuf};
use walkdir::WalkDir;

/// Configuration for ADR check
#[derive(Debug, Clone)]
pub struct AdrCheckArgs {
    pub ledger: PathBuf,
    pub adr_dir: PathBuf,
    pub verbosity: crate::Verbosity,
}

impl Default for AdrCheckArgs {
    fn default() -> Self {
        Self {
            ledger: PathBuf::from("specs/spec_ledger.yaml"),
            adr_dir: PathBuf::from("docs/adr"),
            verbosity: crate::Verbosity::Normal,
        }
    }
}

/// Represents a reference to an ADR in the spec ledger
#[derive(Debug)]
struct AdrReference {
    adr_id: String,
    context: String, // e.g., "Story US-TPL-001", "AC AC-TPL-001"
}

/// Spec ledger structures for parsing ADR references
#[derive(Debug, Deserialize)]
struct SpecLedger {
    #[serde(default)]
    metadata: Option<Metadata>,
    stories: Vec<Story>,
}

#[derive(Debug, Deserialize)]
struct Metadata {
    #[serde(default)]
    adrs: Option<Vec<String>>,
}

#[derive(Debug, Deserialize)]
struct Story {
    id: String,
    #[serde(default, deserialize_with = "deserialize_string_or_vec")]
    adr: Option<Vec<String>>,
    requirements: Vec<Requirement>,
}

#[derive(Debug, Deserialize)]
struct Requirement {
    id: String,
    /// Tags for categorizing requirements (e.g., @tier1, @security).
    /// Future: Used for filtering ADR checks by tag.
    /// See TASK-DX-ADR-FILTERING for planned tag-based ADR validation.
    #[serde(default)]
    #[allow(dead_code)]
    tags: Vec<String>,
    #[serde(default, deserialize_with = "deserialize_string_or_vec")]
    adr: Option<Vec<String>>,
    acceptance_criteria: Vec<AcceptanceCriterion>,
}

#[derive(Debug, Deserialize)]
struct AcceptanceCriterion {
    id: String,
    #[serde(default, deserialize_with = "deserialize_string_or_vec")]
    adr: Option<Vec<String>>,
}

fn deserialize_string_or_vec<'de, D>(deserializer: D) -> Result<Option<Vec<String>>, D::Error>
where
    D: serde::Deserializer<'de>,
{
    #[derive(Deserialize)]
    #[serde(untagged)]
    enum StringOrVec {
        String(String),
        Vec(Vec<String>),
    }

    Option::<StringOrVec>::deserialize(deserializer).map(|opt| match opt {
        Some(StringOrVec::String(s)) => Some(vec![s]),
        Some(StringOrVec::Vec(v)) => Some(v),
        None => None,
    })
}

/// Main ADR check entry point
pub fn run(args: AdrCheckArgs) -> Result<()> {
    let verbose = args.verbosity.is_verbose();
    let quiet = args.verbosity.is_quiet();

    if !quiet {
        println!("{}", "Checking ADR references...".cyan().bold());
    }

    // 1. Collect all ADR references from the ledger
    let references = collect_adr_references(&args.ledger, verbose)?;

    if verbose {
        println!("\nFound {} ADR references in ledger:", references.len());
        for ref_item in &references {
            println!("  {} → {}", ref_item.adr_id.yellow(), ref_item.context.dimmed());
        }
    }

    // 2. Find all ADR files in docs/adr/
    let adr_files = find_adr_files(&args.adr_dir, verbose)?;

    if verbose {
        println!("\nFound {} ADR files:", adr_files.len());
        for adr in &adr_files {
            println!("  {}", adr.green());
        }
    }

    // 3. Validate references
    let mut missing_adrs = Vec::new();
    let referenced_adrs: HashSet<String> = references.iter().map(|r| r.adr_id.clone()).collect();

    for ref_item in &references {
        if !adr_files.contains(&ref_item.adr_id) {
            missing_adrs.push(ref_item);
        }
    }

    // 4. Find unreferenced ADRs
    let unreferenced_adrs: Vec<&String> =
        adr_files.iter().filter(|adr| !referenced_adrs.contains(*adr)).collect();

    // 5. Report results
    let mut has_errors = false;

    if !missing_adrs.is_empty() {
        has_errors = true;
        println!("\n{}", "❌ Missing ADR files:".red().bold());
        for ref_item in &missing_adrs {
            println!("  {} (referenced by {})", ref_item.adr_id.yellow(), ref_item.context);
        }
    }

    if !unreferenced_adrs.is_empty() && !quiet {
        println!("\n{}", "⚠  Unreferenced ADRs (may be orphaned):".yellow().bold());
        for adr in &unreferenced_adrs {
            println!("  {}", adr.dimmed());
        }
        println!(
            "\n  {}",
            "Note: These ADRs exist but aren't referenced in spec_ledger.yaml".dimmed()
        );
        println!("  {}", "They may be deprecated, superseded, or not yet wired in.".dimmed());
    }

    if !has_errors {
        if !quiet {
            println!("\n{}", "✓ All ADR references are valid".green().bold());
            if !unreferenced_adrs.is_empty() {
                println!("  {} unreferenced ADRs (warnings only)", unreferenced_adrs.len());
            }
        }
        Ok(())
    } else {
        anyhow::bail!("ADR validation failed: {} missing ADR files", missing_adrs.len());
    }
}

/// Collect all ADR references from the spec ledger
fn collect_adr_references(ledger_path: &Path, _verbose: bool) -> Result<Vec<AdrReference>> {
    let content = fs::read_to_string(ledger_path)
        .with_context(|| format!("Failed to read ledger: {}", ledger_path.display()))?;

    let ledger: SpecLedger = serde_yaml::from_str(&content)
        .with_context(|| format!("Failed to parse ledger: {}", ledger_path.display()))?;

    let mut references = Vec::new();

    // Collect ADRs from metadata
    if let Some(metadata) = &ledger.metadata
        && let Some(adrs) = &metadata.adrs
    {
        for adr in adrs {
            references.push(AdrReference {
                adr_id: adr.clone(),
                context: "Metadata (template-wide)".to_string(),
            });
        }
    }

    for story in &ledger.stories {
        if let Some(adrs) = &story.adr {
            for adr in adrs {
                references.push(AdrReference {
                    adr_id: adr.clone(),
                    context: format!("Story {}", story.id),
                });
            }
        }

        for req in &story.requirements {
            if let Some(adrs) = &req.adr {
                for adr in adrs {
                    references.push(AdrReference {
                        adr_id: adr.clone(),
                        context: format!("Requirement {} (Story {})", req.id, story.id),
                    });
                }
            }

            for ac in &req.acceptance_criteria {
                if let Some(adrs) = &ac.adr {
                    for adr in adrs {
                        references.push(AdrReference {
                            adr_id: adr.clone(),
                            context: format!("AC {} (Requirement {})", ac.id, req.id),
                        });
                    }
                }
            }
        }
    }

    Ok(references)
}

/// Find all ADR files in docs/adr/ and extract their IDs
fn find_adr_files(adr_dir: &Path, verbose: bool) -> Result<HashSet<String>> {
    if !adr_dir.exists() {
        if verbose {
            println!("  {} ADR directory not found: {}", "⚠".yellow(), adr_dir.display());
        }
        return Ok(HashSet::new());
    }

    let mut adr_ids = HashSet::new();

    for entry in WalkDir::new(adr_dir).min_depth(1).max_depth(1).into_iter().filter_map(|e| e.ok())
    {
        let path = entry.path();
        if path.extension().and_then(|s| s.to_str()) == Some("md")
            && let Some(adr_id) = extract_adr_id(path)
        {
            adr_ids.insert(adr_id);
        }
    }

    Ok(adr_ids)
}

/// Extract ADR ID from filename (e.g., "0001-hexagonal-architecture.md" → "ADR-0001")
fn extract_adr_id(path: &Path) -> Option<String> {
    path.file_stem().and_then(|s| s.to_str()).and_then(|name| {
        // Match pattern like "0001-title" or "ADR-0001-title"
        if name.starts_with("ADR-") {
            // Already has ADR- prefix, take "ADR-NNNN" part
            name.splitn(3, '-').take(2).collect::<Vec<_>>().join("-").into()
        } else {
            // Assumes format "NNNN-title"
            name.split('-').next().map(|num| format!("ADR-{}", num))
        }
    })
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_extract_adr_id() {
        assert_eq!(extract_adr_id(Path::new("0001-hexagonal.md")), Some("ADR-0001".to_string()));
        assert_eq!(
            extract_adr_id(Path::new("ADR-0002-nix-first.md")),
            Some("ADR-0002".to_string())
        );
        assert_eq!(
            extract_adr_id(Path::new("0042-meaning-of-life.md")),
            Some("ADR-0042".to_string())
        );
    }
}

use anyhow::{Context, Result};
use colored::Colorize;
use std::fs;
use std::path::Path;
use std::process::Command;

pub fn run(title: &str) -> Result<()> {
    println!("{}", "📝 Creating new ADR...".blue().bold());
    println!();

    // Find next ADR number
    let adr_dir = Path::new("docs/adr");
    let next_num = find_next_adr_number(adr_dir)?;

    // Create slug from title
    let slug = title
        .to_lowercase()
        .replace(char::is_whitespace, "-")
        .chars()
        .filter(|c| c.is_alphanumeric() || *c == '-')
        .collect::<String>();

    let adr_id = format!("ADR-{:04}", next_num);
    let filename = format!("{:04}-{}.md", next_num, slug);
    let filepath = adr_dir.join(&filename);

    // Get author from git config
    let author = get_git_user().unwrap_or_else(|_| "Unknown".to_string());

    // Get today's date
    let date = chrono::Local::now().format("%Y-%m-%d").to_string();

    // Read template
    let template_path = Path::new("docs/templates/ADR-TEMPLATE.md");
    if !template_path.exists() {
        anyhow::bail!("ADR template not found at {}", template_path.display());
    }

    let template = fs::read_to_string(template_path)?;

    // Fill in template
    let content = template
        .replace("# ADR-XXXX: [Title]", &format!("# {}: {}", adr_id, title))
        .replace(
            "**Status**: [Proposed | Accepted | Deprecated | Superseded by ADR-YYYY]",
            "**Status**: Proposed",
        )
        .replace("**Date**: YYYY-MM-DD", &format!("**Date**: {}", date))
        .replace("**Authors**: [Author names or teams]", &format!("**Authors**: {}", author));

    // Write file
    fs::write(&filepath, content)?;

    println!("{} Created {}", "✓".green(), filepath.display());
    println!();
    println!("{}", "Next steps:".bold());
    println!("  1. Edit {}", filepath.display());
    println!("  2. Link this ADR in specs/spec_ledger.yaml:");
    println!("     - Metadata-level ADRs: under metadata.adrs");
    println!("     - Story-level: under story.adr");
    println!("     - Requirement-level: under requirement.adr");
    println!("     - AC-level: under acceptance_criteria.adr");
    println!("  3. Run: {}", "cargo xtask adr-check".cyan());
    println!("  4. Review & discuss; set Status: Accepted when settled");

    Ok(())
}

fn find_next_adr_number(adr_dir: &Path) -> Result<u32> {
    if !adr_dir.exists() {
        anyhow::bail!("ADR directory not found: {}", adr_dir.display());
    }

    let mut max_num = 0;

    for entry in fs::read_dir(adr_dir)? {
        let entry = entry?;
        let filename = entry.file_name();
        let filename_str = filename.to_string_lossy();

        // Parse "0001-title.md" -> 1
        if let Some(num_str) = filename_str.split('-').next()
            && let Ok(num) = num_str.parse::<u32>()
        {
            max_num = max_num.max(num);
        }
    }

    Ok(max_num + 1)
}

fn get_git_user() -> Result<String> {
    let output = Command::new("git")
        .args(["config", "user.name"])
        .output()
        .context("Failed to get git user.name")?;

    if output.status.success() {
        let name = String::from_utf8_lossy(&output.stdout).trim().to_string();
        if !name.is_empty() {
            return Ok(name);
        }
    }

    anyhow::bail!("Git user.name not configured")
}

