use anyhow::Result;
use colored::Colorize;
use std::env;

pub fn run() -> Result<()> {
    println!("{}", "🔄 Running CI checks locally...".blue().bold());
    println!();

    let mut failed = Vec::new();

    // Step 1: Environment validation
    println!("{}", "[1/4] Environment validation...".bold());
    match crate::commands::doctor::run() {
        Ok(_) => println!("{} doctor passed\n", "✓".green()),
        Err(e) => {
            println!("{} doctor failed\n", "✗".red());
            eprintln!("{}", e);
            failed.push("doctor");
        }
    }

    // Step 2: Template selftest
    println!("{}", "[2/4] Template selftest...".bold());

    // Prevent recursive BDD execution when ci-local runs inside the acceptance suite
    let prev_skip_bdd = env::var("XTASK_SKIP_BDD").ok();
    // SAFETY: Tests flip this flag to avoid recursive BDD execution during nested selftest runs.
    unsafe {
        env::set_var("XTASK_SKIP_BDD", "1");
    }
    let selftest_result = crate::commands::selftest::run_with_verbosity(crate::Verbosity::Normal);
    unsafe {
        if let Some(prev) = prev_skip_bdd {
            env::set_var("XTASK_SKIP_BDD", prev);
        } else {
            env::remove_var("XTASK_SKIP_BDD");
        }
    }

    match selftest_result {
        Ok(_) => println!("{} selftest passed\n", "✓".green()),
        Err(e) => {
            println!("{} selftest failed\n", "✗".red());
            eprintln!("{}", e);
            failed.push("selftest");
        }
    }

    // Step 3: Security audit (optional - only if tools available)
    println!("{}", "[3/4] Security audit...".bold());
    match crate::commands::audit::run() {
        Ok(_) => println!("{} audit passed\n", "✓".green()),
        Err(e) => {
            // Audit failures are warnings in ci-local (not hard failures)
            println!("{} audit had issues (see above)\n", "⚠".yellow());
            eprintln!("{}", e);
        }
    }

    // Step 4: Documentation consistency
    println!("{}", "[4/4] Documentation consistency...".bold());
    match crate::commands::docs_check::run() {
        Ok(_) => println!("{} docs-check passed\n", "✓".green()),
        Err(e) => {
            println!("{} docs-check failed\n", "✗".red());
            eprintln!("{}", e);
            failed.push("docs-check");
        }
    }

    // Final: Check working tree
    let skip_git_status = env::var("XTASK_SKIP_GIT_STATUS").is_ok()
        || env::var("XTASK_LOW_RESOURCES").unwrap_or_default() == "1";

    if skip_git_status {
        println!("{} Skipping git status check (low-resource/test mode)\n", "⚠".yellow());
    } else {
        println!("{}", "Checking working tree...".bold());
        let output = std::process::Command::new("git").args(["status", "--porcelain"]).output()?;

        let status = String::from_utf8_lossy(&output.stdout);
        if !status.trim().is_empty() {
            println!("{} Working tree is dirty\n", "✗".red());
            println!("{}", status);
            failed.push("git-clean");
        } else {
            println!("{} Working tree clean\n", "✓".green());
        }
    }

    // Summary
    println!("{}", "=".repeat(40));
    if failed.is_empty() {
        println!("{}", "✓ CI-local passed! Ready to push.".green().bold());
        println!();
        println!("{}", "Next steps:".bold());
        println!("  • Review changes: {}", "git diff".cyan());
        println!("  • Push: {}", "git push".cyan());
    } else {
        println!("{}", "✗ CI-local failed".red().bold());
        println!();
        println!("Failed checks:");
        for check in &failed {
            println!("  • {}", check);
        }
        println!();
        println!("{}", "Fix issues above and re-run: cargo xtask ci-local".yellow());
        anyhow::bail!("{} check(s) failed", failed.len());
    }

    Ok(())
}

use anyhow::Result;
use colored::Colorize;
use std::fs;
use std::path::Path;

pub fn run() -> Result<()> {
    println!("{}", "🧹 Cleaning workspace...".blue().bold());
    println!();

    let mut cleaned = 0;
    let mut skipped = 0;

    // Clean target directory
    if Path::new("target").exists() {
        print!("Removing target/... ");
        match fs::remove_dir_all("target") {
            Ok(_) => {
                println!("{}", "✓ Removed".green());
                cleaned += 1;
            }
            Err(e) => {
                println!("{} {}", "✗ Failed:".red(), e);
                skipped += 1;
            }
        }
    } else {
        println!("target/... {} Already clean", "✓".dimmed());
    }

    // Clean LLM bundles
    if Path::new(".llm/bundle").exists() {
        print!("Removing .llm/bundle/... ");
        match fs::remove_dir_all(".llm/bundle") {
            Ok(_) => {
                println!("{}", "✓ Removed".green());
                cleaned += 1;
            }
            Err(e) => {
                println!("{} {}", "✗ Failed:".red(), e);
                skipped += 1;
            }
        }
    } else {
        println!(".llm/bundle/... {} Already clean", "✓".dimmed());
    }

    // Clean generated docs
    if Path::new("docs/feature_status.md").exists() {
        print!("Removing docs/feature_status.md... ");
        match fs::remove_file("docs/feature_status.md") {
            Ok(_) => {
                println!("{}", "✓ Removed".green());
                cleaned += 1;
            }
            Err(e) => {
                println!("{} {}", "✗ Failed:".red(), e);
                skipped += 1;
            }
        }
    } else {
        println!("docs/feature_status.md... {} Already clean", "✓".dimmed());
    }

    // Clean node_modules if present
    if Path::new("node_modules").exists() {
        print!("Removing node_modules/... ");
        match fs::remove_dir_all("node_modules") {
            Ok(_) => {
                println!("{}", "✓ Removed".green());
                cleaned += 1;
            }
            Err(e) => {
                println!("{} {}", "✗ Failed:".red(), e);
                skipped += 1;
            }
        }
    }

    println!();
    if cleaned > 0 {
        println!("{} Cleaned {} item(s)", "✓".green().bold(), cleaned);
    } else {
        println!("{} Workspace already clean", "✓".green().bold());
    }

    if skipped > 0 {
        println!("{} {} item(s) could not be cleaned", "⚠".yellow(), skipped);
    }

    Ok(())
}

use anyhow::{Result, anyhow};
use serde_yaml::Value;
use std::fs;

/// Minimal config-validate: parse `specs/config_schema.yaml` and perform basic checks.
pub fn run(env: &str) -> Result<()> {
    let text = fs::read_to_string("specs/config_schema.yaml")
        .map_err(|e| anyhow!("failed to read config schema: {}", e))?;

    let doc: Value = serde_yaml::from_str(&text)?;

    // Basic validations
    if doc.get("settings").is_none() && doc.get("secrets").is_none() {
        anyhow::bail!("config schema must contain at least one of 'settings' or 'secrets'");
    }

    println!("Parsed config schema for env='{}' successfully", env);
    if let Some(Value::Sequence(secrets)) = doc.get("secrets") {
        for s in secrets.iter() {
            if let Value::Mapping(m) = s
                && !m.contains_key(Value::from("key"))
            {
                anyhow::bail!("each secret entry must have a 'key' field");
            }
        }
    }

    println!("Basic schema checks passed");
    println!("Note: this is a lightweight validator; environment resolution not implemented yet.");

    Ok(())
}

use anyhow::{Context, Result};
use colored::Colorize;
use serde::Deserialize;
use std::process::Command;

/// Coverage baseline target (65%)
const COVERAGE_BASELINE: f64 = 65.0;

/// Tarpaulin JSON output structure (partial, only what we need)
#[derive(Debug, Deserialize)]
struct TarpaulinReport {
    coverage: f64,
}

pub fn run() -> Result<()> {
    run_with_baseline(COVERAGE_BASELINE)?;
    Ok(())
}

pub fn run_with_baseline(baseline: f64) -> Result<f64> {
    println!("{}", "Running test coverage analysis".blue().bold());
    println!();

    // Check if cargo-tarpaulin is available
    let has_tarpaulin = which::which("cargo-tarpaulin").is_ok();

    if !has_tarpaulin {
        println!("{}", "⚠️  cargo-tarpaulin not found".yellow());
        println!("Install via:");
        println!("  Nix: {}", "nix develop".cyan());
        println!("  Or manually: {}", "cargo install cargo-tarpaulin".cyan());
        println!();
        println!("{}", "Coverage check skipped (tool not available)".yellow());
        return Ok(0.0);
    }

    println!("Generating coverage report (this may take a while)...");

    // Run cargo tarpaulin with JSON output
    // --out Json: JSON output for machine parsing
    // --exclude-files tests: Don't count test files themselves
    // --timeout 300: 5-minute timeout per test
    // --workspace: Cover all workspace crates
    // --exclude acceptance xtask: Don't analyze BDD tests and xtask
    let mut cmd = Command::new("cargo");
    cmd.args([
        "tarpaulin",
        "--out",
        "Json",
        "--exclude-files",
        "tests",
        "--timeout",
        "300",
        "--workspace",
        "--exclude",
        "acceptance",
        "--exclude",
        "xtask",
    ]);

    // Suppress stderr noise (only matters on failure)
    let output = cmd.output().context("Failed to run cargo-tarpaulin")?;

    if !output.status.success() {
        let stderr = String::from_utf8_lossy(&output.stderr);
        eprintln!("{}", "✗ Coverage generation failed".red());
        eprintln!("{}", stderr);
        anyhow::bail!("cargo-tarpaulin exited with non-zero status");
    }

    // Parse JSON output
    let stdout = String::from_utf8_lossy(&output.stdout);
    let report: TarpaulinReport =
        serde_json::from_str(&stdout).context("Failed to parse tarpaulin JSON output")?;

    let coverage_pct = report.coverage;

    println!();
    println!("{}", "Coverage Report:".bold());
    println!("  Coverage: {:.2}%", coverage_pct);
    println!("  Baseline: {:.2}%", baseline);

    if coverage_pct >= baseline {
        println!();
        println!(
            "{} Coverage target met! ({:.2}% >= {:.2}%)",
            "✓".green().bold(),
            coverage_pct,
            baseline
        );
        Ok(coverage_pct)
    } else {
        println!();
        println!(
            "{} Coverage below baseline ({:.2}% < {:.2}%)",
            "✗".red().bold(),
            coverage_pct,
            baseline
        );
        println!();
        println!("{}", "Recovery options:".bold());
        println!("  • Add tests for uncovered code");
        println!("  • Run {} to see detailed coverage report", "cargo tarpaulin --out Html".cyan());
        println!("  • Review coverage gaps in {}", "target/coverage/".dimmed());

        anyhow::bail!("Coverage below baseline: {:.2}% < {:.2}%", coverage_pct, baseline);
    }
}

