/// Get workspace root directory
fn get_workspace_root() -> Result<PathBuf> {
    let current_dir = std::env::current_dir().context("Failed to get current directory")?;

    // Try to find Cargo.toml in workspace root
    let mut check_dir = current_dir.clone();
    for _ in 0..3 {
        let cargo_toml = check_dir.join("Cargo.toml");
        if cargo_toml.exists() {
            // Verify it's the workspace root by checking for infra directory
            if check_dir.join("infra").exists() {
                return Ok(check_dir);
            }
        }
        if let Some(parent) = check_dir.parent() {
            check_dir = parent.to_path_buf();
        } else {
            break;
        }
    }

    // Fallback: assume we're running from workspace root
    Ok(current_dir)
}

use anyhow::{Context, Result};
use chrono::Utc;
use colored::Colorize;
use std::fs;
use std::path::PathBuf;

pub struct DesignNewArgs {
    pub id: String,
    pub title: String,
    pub requirements: Vec<String>,
    pub adrs: Vec<String>,
    pub owner: Option<String>,
}

pub fn run(args: DesignNewArgs) -> Result<()> {
    let manifest_dir = PathBuf::from(env!("CARGO_MANIFEST_DIR"));
    let root = manifest_dir.parent().expect("workspace root").parent().expect("repo root");

    let design_dir = root.join("docs/design");
    fs::create_dir_all(&design_dir)
        .with_context(|| format!("Failed to create design dir: {}", design_dir.display()))?;

    let slug = slugify(&args.title);
    let file_name = format!("{}-{}.md", args.id.to_lowercase(), slug);
    let path = design_dir.join(&file_name);

    if path.exists() {
        anyhow::bail!("Design doc already exists at {}", path.display());
    }

    let today = Utc::now().date_naive().to_string();
    let requirements_str = if args.requirements.is_empty() {
        "[]".to_string()
    } else {
        format!(
            "[{}]",
            args.requirements.iter().map(|r| format!("\"{}\"", r)).collect::<Vec<_>>().join(", ")
        )
    };
    let adrs_str = if args.adrs.is_empty() {
        "[]".to_string()
    } else {
        format!(
            "[{}]",
            args.adrs.iter().map(|a| format!("\"{}\"", a)).collect::<Vec<_>>().join(", ")
        )
    };
    let owner = args.owner.as_deref().unwrap_or("platform");

    let content = format!(
        r#"---
doc_type: design_doc
id: {id}
title: "{title}"
stories: []
requirements: {requirements}
acs: []
adrs: {adrs}
status: draft
last_reviewed: {date}
owner: "{owner}"
---

# {title}

## 1. Context

- Brief description of the problem being solved
- Link to user stories and requirements
- Why this design is needed

## 2. High-Level Design

- Key components and their responsibilities
- Interactions and data flows
- Architecture diagrams (optional)

## 3. Edge Cases & Failure Modes

- Known tricky scenarios
- How errors are surfaced and handled
- Degradation and fallback strategies

## 4. Tests & Invariants

- How BDD/ACs validate this design
- Critical invariants that must hold
- Testing strategy

## 5. Open Questions / Future Work

- Items to be determined
- Explicit non-goals
- Follow-up work or extensions
"#,
        id = args.id,
        title = args.title,
        requirements = requirements_str,
        adrs = adrs_str,
        date = today,
        owner = owner
    );

    fs::write(&path, content).with_context(|| format!("Writing {}", path.display()))?;

    let rel_path = path.strip_prefix(root).unwrap_or(&path);
    println!("{} Created design doc at {}", "✓".green(), rel_path.display());
    println!();
    println!("{}", "Next steps:".bold());
    println!("  • Add this entry to specs/doc_index.yaml:");
    println!("    - id: {}", args.id);
    println!("      file: {}", rel_path.display());
    println!("      doc_type: design_doc");
    println!("      stories: []");
    println!("      requirements: {}", requirements_str);
    println!("      acs: []");
    println!("      adrs: {}", adrs_str);
    println!("  • Fill in the design sections in the new file.");
    println!("  • Run: {}", "cargo xtask docs-check".cyan());

    Ok(())
}

fn slugify(title: &str) -> String {
    title
        .to_lowercase()
        .chars()
        .map(|c| if c.is_ascii_alphanumeric() { c } else { '-' })
        .collect::<String>()
        .split('-')
        .filter(|s| !s.is_empty())
        .collect::<Vec<_>>()
        .join("-")
}

use anyhow::{Result, anyhow};
use colored::Colorize;
use std::path::Path;
use std::process::{Command, Stdio};

pub fn run() -> Result<()> {
    println!("{}", "🦀 Rust-as-Spec dev-up starting...".bold());

    // 1. Install pre-commit hooks if missing
    println!("→ Pre-commit hooks check...");
    let hook_path = Path::new(".git").join("hooks").join("pre-commit");
    if !hook_path.exists() {
        println!("  Installing pre-commit hooks...");
        crate::commands::install_hooks::run()?;
    } else {
        println!("  {}", "✓ Pre-commit hooks already installed".green());
    }

    // 2. Check Docker availability
    println!("→ Docker status check...");
    let docker_ok = Command::new("docker")
        .arg("ps")
        .stdout(Stdio::null())
        .stderr(Stdio::null())
        .status()
        .map(|s| s.success())
        .unwrap_or(false);

    if !docker_ok {
        println!("  {}", "⚠ Docker status: not running".yellow());
        println!("  Please start Docker and run:");
        println!("  {}", "docker compose up -d".cyan());
    } else if Path::new("docker-compose.yaml").exists() {
        println!("  Docker status: running");
        println!("  Ensuring local services are running (docker compose up -d)...");
        let _ = Command::new("docker").arg("compose").arg("up").arg("-d").status();
    } else {
        println!("  Docker status: running (no docker-compose.yaml found)");
    }

    // 3. Light governance check (low-resource mode)
    println!("→ Running governance check...");
    let low_resource_mode = std::env::var("XTASK_LOW_RESOURCES").unwrap_or_default() == "1";
    if low_resource_mode {
        println!("  Running in low-resource mode");
    }

    // Use current executable to avoid file locking issues
    let current_exe = std::env::current_exe().unwrap_or_else(|_| "xtask".into());
    let mut cmd = Command::new(current_exe);
    cmd.env("XTASK_LOW_RESOURCES", "1").arg("check");
    let status = cmd.status()?;
    if !status.success() {
        println!(
            "{}",
            "❌ Governance check failed. Please fix issues above before continuing.".red()
        );
        return Err(anyhow!("governance check failed"));
    }

    // 4. Print next steps
    println!();
    println!("{}", "✅ dev-up complete.".green().bold());
    println!("Next steps:");
    println!("  1. {}", "cargo run -p app-http".cyan());
    println!("  2. Open {}", "http://localhost:8080/ui".cyan());

    Ok(())
}

