            ("rustc 1.90.1 (def789012 2024-02-01)", "1.90.1"),
            ("rustc 1.91.0 (ghi345678 2024-03-01)", "1.91.0"),
            ("  rustc 1.89.0 (abc123 2024-01-01)  ", "1.89.0"), // with whitespace
        ];

        for (input, expected) in test_cases {
            let result = extract_version_number(input);
            assert_eq!(result, expected, "Failed to extract version from: {}", input);
        }
    }

    #[test]
    fn test_extract_version_number_handles_malformed() {
        // Test that malformed input doesn't panic
        let malformed = vec!["", "rustc", "some random text"];

        for input in malformed {
            let result = extract_version_number(input);
            // Should return "unknown" for malformed input
            assert!(
                result == "unknown" || !result.is_empty(),
                "Should handle malformed input: {}",
                input
            );
        }
    }

    #[test]
    fn test_check_sccache_health_when_not_configured() {
        // When RUSTC_WRAPPER is not set, sccache check should pass
        // This test validates the function logic without requiring sccache to be installed
        unsafe {
            std::env::remove_var("RUSTC_WRAPPER");
        }

        let result = check_sccache_health();
        assert!(result.is_ok(), "Should succeed when RUSTC_WRAPPER not set");
        assert!(result.unwrap().contains("Not configured"), "Should report not configured");
    }

    #[test]
    fn test_check_sccache_health_with_other_wrapper() {
        // When RUSTC_WRAPPER is set to something else, should report it
        unsafe {
            std::env::set_var("RUSTC_WRAPPER", "some-other-wrapper");
        }

        let result = check_sccache_health();
        assert!(result.is_ok(), "Should succeed with other wrapper");
        assert!(result.unwrap().contains("RUSTC_WRAPPER=some-other-wrapper"));

        unsafe {
            std::env::remove_var("RUSTC_WRAPPER");
        }
    }
}

//! Show environment detection mode for debugging CI/automation contexts.
//!
//! This command displays the current environment mode based on the centralized
//! detection in `crate::env`. Useful for:
//! - Debugging why BDD tests are being skipped
//! - Verifying CI detection is working
//! - Understanding which env vars are being honored

use anyhow::Result;
use colored::Colorize;
use std::env;

use crate::env::{describe_mode, is_ci, is_low_resources, is_noninteractive, should_skip_bdd};

pub struct EnvModeArgs {
    pub json: bool,
}

pub fn run(args: EnvModeArgs) -> Result<()> {
    let mode = describe_mode();
    let ci = is_ci();
    let noninteractive = is_noninteractive();
    let low_resources = is_low_resources();
    let skip_bdd = should_skip_bdd();

    // Collect raw env var values for debugging
    let ci_var = env::var("CI").ok();
    let github_actions = env::var("GITHUB_ACTIONS").ok();
    let gitlab_ci = env::var("GITLAB_CI").ok();
    let noninteractive_var = env::var("XTASK_NONINTERACTIVE").ok();
    let low_resources_var = env::var("XTASK_LOW_RESOURCES").ok();
    let skip_bdd_var = env::var("XTASK_SKIP_BDD").ok();
    let in_nix_shell = env::var("IN_NIX_SHELL").ok();

    if args.json {
        let output = serde_json::json!({
            "mode": mode,
            "flags": {
                "is_ci": ci,
                "is_noninteractive": noninteractive,
                "is_low_resources": low_resources,
                "should_skip_bdd": skip_bdd
            },
            "env_vars": {
                "CI": ci_var,
                "GITHUB_ACTIONS": github_actions,
                "GITLAB_CI": gitlab_ci,
                "XTASK_NONINTERACTIVE": noninteractive_var,
                "XTASK_LOW_RESOURCES": low_resources_var,
                "XTASK_SKIP_BDD": skip_bdd_var,
                "IN_NIX_SHELL": in_nix_shell
            }
        });
        println!("{}", serde_json::to_string_pretty(&output)?);
    } else {
        println!("{}", "Environment Mode".bold());
        println!("  Mode: {}", mode.green());
        println!();

        println!("{}", "Detection Flags".bold());
        println!("  is_ci:            {}", format_bool(ci));
        println!("  is_noninteractive: {}", format_bool(noninteractive));
        println!("  is_low_resources: {}", format_bool(low_resources));
        println!("  should_skip_bdd:  {}", format_bool(skip_bdd));
        println!();

        println!("{}", "Raw Environment Variables".bold());
        println!("  CI=               {}", format_var(&ci_var));
        println!("  GITHUB_ACTIONS=   {}", format_var(&github_actions));
        println!("  GITLAB_CI=        {}", format_var(&gitlab_ci));
        println!("  XTASK_NONINTERACTIVE= {}", format_var(&noninteractive_var));
        println!("  XTASK_LOW_RESOURCES=  {}", format_var(&low_resources_var));
        println!("  XTASK_SKIP_BDD=       {}", format_var(&skip_bdd_var));
        println!("  IN_NIX_SHELL=         {}", format_var(&in_nix_shell));
    }

    Ok(())
}

fn format_bool(value: bool) -> String {
    if value { "true".green().to_string() } else { "false".dimmed().to_string() }
}

fn format_var(value: &Option<String>) -> String {
    match value {
        Some(v) => format!("\"{}\"", v).cyan().to_string(),
        None => "(unset)".dimmed().to_string(),
    }
}

use crate::run_cmd;
use anyhow::Result;
use colored::Colorize;
use std::process::Command;

pub fn run() -> Result<()> {
    println!("{}", "🎨 Formatting all code...".blue().bold());
    println!();

    let mut formatted = 0;

    // Format Rust code
    print!("Formatting Rust (cargo fmt --all)... ");
    print!("Formatting Rust (cargo fmt --all)... ");
    let mut cmd = crate::cargo_cmd("fmt", &["--all"]);
    match run_cmd(&mut cmd) {
        Ok(_) => {
            println!("{}", "✓ Done".green());
            formatted += 1;
        }
        Err(e) => {
            println!("{} {}", "✗ Failed:".red(), e);
        }
    }

    // Format YAML files (if yq is available)
    if which::which("yq").is_ok() {
        print!("Checking YAML formatting... ");
        // Note: yq can validate but auto-formatting YAML is risky (loses comments)
        // So we just validate here
        let yaml_files = ["specs/spec_ledger.yaml", ".llm/contextpack.yaml"];
        let mut valid = true;
        for file in &yaml_files {
            if std::path::Path::new(file).exists() {
                let mut cmd = Command::new("yq");
                cmd.args(["eval", ".", file]);
                cmd.stdout(std::process::Stdio::null());
                if cmd.status().is_err() {
                    valid = false;
                    break;
                }
            }
        }
        if valid {
            println!("{} Valid", "✓".green());
        } else {
            println!("{} Issues found", "⚠".yellow());
        }
    }

    // Format JSON files (if jq is available)
    if which::which("jq").is_ok() {
        print!("Formatting JSON (if any)... ");
        // This would format any .json files in the repo
        // For now, just validate
        println!("{} Skipped (manual)", "✓".dimmed());
    }

    println!();
    if formatted > 0 {
        println!("{} Formatting complete", "✓".green().bold());
    } else {
        println!("{} No formatting applied", "⚠".yellow());
    }

    Ok(())
}

use anyhow::{Context, Result};
use serde::{Deserialize, Serialize};
use std::fs;
