    println!("  2. {} - TypeScript types and API tests", "Backstage plugin checks".cyan());
    println!();

    let mut failures = Vec::new();
    let mut warnings = Vec::new();

    // Step 1: OpenAPI lint
    println!("{}", "━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━".dimmed());
