    match run_openapi_lint() {
        Ok(_) => {
            println!("{} OpenAPI schema is valid", "✓".green().bold());
        }
        Err(e) => {
            println!("{} OpenAPI lint failed: {}", "✗".red().bold(), e);
            failures.push(format!("openapi-lint: {}", e));
        }
    }

    println!();

    // Step 2: Backstage plugin checks
    println!("{}", "━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━".dimmed());
