    println!("{}", "📌 Pinning GitHub Actions to SHAs...".blue());

    // Git config (best effort)
    let _ = Command::new("git").args(["config", "user.name", "gha-bot"]).output();
    let _ = Command::new("git")
        .args(["config", "user.email", "gha-bot@users.noreply.github.com"])
        .output();

    // Checkout branch
    let branch = "maintenance/pin-actions";
    println!("Checking out branch: {}", branch);
    run_cmd(Command::new("git").args(["checkout", "-B", branch]))?;

    let mut changed = false;
    let root = project_root();
    let workflows_dir = root.join(".github/workflows");

    // Regex to find "uses: owner/repo@ref"
    // Matches: uses: <owner>/<repo>@<ref>
    let uses_re = Regex::new(r"uses:\s*([\w.-]+)/([\w.-]+)@([\w./-]+)").unwrap();

    // Regex to check if it's already a SHA (40 hex chars)
    let sha_re = Regex::new(r"^[0-9a-f]{40}$").unwrap();

    let pattern = workflows_dir.join("*.yml");
    let pattern_str = pattern.to_str().context("Invalid path")?;

    for entry in glob(pattern_str)? {
        let path = entry?;
        let content = fs::read_to_string(&path)?;
        let mut file_changed = false;

        // Replace refs with SHAs
        let new_content = uses_re
            .replace_all(&content, |caps: &Captures| {
                let owner = &caps[1];
                let repo = &caps[2];
                let ref_ = &caps[3];

                if sha_re.is_match(ref_) {
                    return caps[0].to_string(); // Already a SHA
                }

                print!("Resolving {}/{}@{}... ", owner, repo, ref_);

                if let Some(sha) = resolve_sha(owner, repo, ref_) {
                    println!("{}", sha.green());
                    file_changed = true;
                    format!("uses: {}/{}@{}", owner, repo, sha)
                } else {
                    println!("{}", "Failed".red());
                    eprintln!("Warning: Could not resolve {}/{}@{}", owner, repo, ref_);
                    caps[0].to_string()
                }
            })
            .to_string();

        if file_changed && new_content != content {
            fs::write(&path, new_content)?;
            changed = true;
            println!("Updated {}", path.display());
        }
    }

    if changed {
        println!("{}", "Committing changes...".blue());
        run_cmd(Command::new("git").args(["add", ".github/workflows"]))?;
        run_cmd(Command::new("git").args(["commit", "-m", "Pin GitHub Actions to commit SHAs"]))?;

        println!("{}", "Pushing changes...".blue());
        run_cmd(Command::new("git").args(["push", "-u", "origin", branch, "--force"]))?;

        println!("{}", "Creating PR...".blue());
        // Best effort PR creation
        let mut pr_cmd = Command::new("gh");
        pr_cmd.args([
            "pr",
            "create",
            "--fill",
            "--title",
            "Pin Actions to SHAs",
            "--body",
            "Automated hard-pinning of GitHub Actions.",
        ]);
        if let Err(e) = run_cmd(&mut pr_cmd) {
            println!("{} Failed to create PR (it might already exist): {}", "⚠".yellow(), e);
        }
    } else {
        println!("{}", "No changes needed.".green());
    }

    Ok(())
}

fn resolve_sha(owner: &str, repo: &str, ref_: &str) -> Option<String> {
    // Try commits endpoint
    // gh api repos/:owner/:repo/commits/:ref --jq .sha
    let output = Command::new("gh")
        .args(["api", &format!("repos/{}/{}/commits/{}", owner, repo, ref_), "--jq", ".sha"])
        .output()
        .ok()?;

    if output.status.success() {
        let sha = String::from_utf8_lossy(&output.stdout).trim().to_string();
        if !sha.is_empty() {
            return Some(sha);
        }
    }

    // Try tags endpoint
    // gh api repos/:owner/:repo/git/ref/tags/:ref --jq .object.sha
    let output = Command::new("gh")
        .args([
            "api",
            &format!("repos/{}/{}/git/ref/tags/{}", owner, repo, ref_),
            "--jq",
            ".object.sha",
        ])
        .output()
        .ok()?;

    if output.status.success() {
        let sha = String::from_utf8_lossy(&output.stdout).trim().to_string();
        if !sha.is_empty() {
            return Some(sha);
        }
    }

    None
}

use anyhow::{Context, Result};
use chrono::{DateTime, Utc};
use colored::Colorize;
use serde::Serialize;
use std::fs;
use std::path::{Path, PathBuf};
use std::process::Command;
use std::time::SystemTime;

/// Custom error type for policy tests
#[derive(Debug)]
pub enum PolicyTestError {
    ConftestNotFound(String),
    Other(anyhow::Error),
}

#[derive(Serialize)]
struct PolicyStatusReport {
    timestamp: String,
    summary: String,
    details: Vec<PolicyResult>,
}

#[derive(Serialize)]
struct PolicyResult {
    name: String,
    status: String,
}

impl std::fmt::Display for PolicyTestError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            PolicyTestError::ConftestNotFound(msg) => write!(f, "{}", msg),
            PolicyTestError::Other(e) => write!(f, "{}", e),
        }
    }
}

impl std::error::Error for PolicyTestError {}

impl From<anyhow::Error> for PolicyTestError {
    fn from(e: anyhow::Error) -> Self {
        PolicyTestError::Other(e)
    }
}

/// Policy areas to test
const POLICY_AREAS: &[(&str, &str)] = &[
    ("Ledger", "ledger"),
    ("Features", "features"),
    ("Flags", "flags"),
    ("Privacy", "privacy"),
    ("Template Core", "template_core"),
    ("LLM", "llm"),
    ("Kubernetes", "k8s"),
];

/// Run conftest policy tests
pub fn run() -> Result<(), PolicyTestError> {
    // Check if conftest is available
    check_conftest_available()?;

    let workspace_root = get_workspace_root()?;
    let policy_dir = workspace_root.join("policy");
    let testdata_dir = policy_dir.join("testdata");

    if !policy_dir.exists() {
        return Err(PolicyTestError::Other(anyhow::anyhow!(
            "Policy directory not found: {}",
            policy_dir.display()
        )));
    }

    if !testdata_dir.exists() {
        return Err(PolicyTestError::Other(anyhow::anyhow!(
            "Policy testdata directory not found: {}",
            testdata_dir.display()
        )));
    }

    println!("Testing Rego policies...\n");

    let mut total_tests = 0;
    let mut failed_tests = 0;
    let mut policy_results = Vec::new();

    // Run tests for each policy area
    for (name, area) in POLICY_AREAS {
        let policy_file = policy_dir.join(format!("{}.rego", area));

        if !policy_file.exists() {
            println!("{} Policy ({}):", name, policy_file.display());
            println!("  {} Policy file not found, skipping\n", "⚠".yellow());
            continue;
        }

        println!("{} Policy ({}):", name, policy_file.display());

        // Find test fixtures for this policy area
        let fixtures = find_test_fixtures(&testdata_dir, area)?;

        if fixtures.is_empty() {
            println!("  {} No test fixtures found, skipping\n", "⚠".yellow());
            continue;
        }

        let mut area_failed = 0;

        // Run tests for each fixture
        for (fixture_path, should_pass) in fixtures {
            let fixture_name =
                fixture_path.file_name().and_then(|n| n.to_str()).unwrap_or("unknown");

            let result = run_conftest_test(&policy_file, &fixture_path)?;

            total_tests += 1;

            match (result, should_pass) {
                (true, true) => {
                    println!("  {} {} (correctly passed)", "✓".green(), fixture_name);
                }
                (false, false) => {
                    println!("  {} {} (correctly failed)", "✓".green(), fixture_name);
                }
                (true, false) => {
                    println!("  {} {} (expected fail, got pass)", "✗".red(), fixture_name);
                    failed_tests += 1;
                    area_failed += 1;
                }
                (false, true) => {
                    println!("  {} {} (expected pass, got fail)", "✗".red(), fixture_name);
                    failed_tests += 1;
                    area_failed += 1;
                }
            };
        }

        policy_results.push(PolicyResult {
            name: name.to_string(),
            status: if area_failed == 0 { "pass".to_string() } else { "fail".to_string() },
        });

        println!();
    }

    // Write policy status JSON
    let report = PolicyStatusReport {
        timestamp: DateTime::<Utc>::from(SystemTime::now()).to_rfc3339(),
        summary: if failed_tests == 0 { "pass".to_string() } else { "fail".to_string() },
        details: policy_results,
    };

    let target_dir = workspace_root.join("target");
    fs::create_dir_all(&target_dir).map_err(|e| PolicyTestError::Other(e.into()))?;

    let json =
        serde_json::to_string_pretty(&report).map_err(|e| PolicyTestError::Other(e.into()))?;
    fs::write(target_dir.join("policy_status.json"), json)
        .map_err(|e| PolicyTestError::Other(e.into()))?;

    // Summary
    if failed_tests == 0 && total_tests > 0 {
        println!("{} All {} policy tests passed!", "✓".green(), total_tests);
        Ok(())
    } else if total_tests == 0 {
        println!("{} No policy tests found", "⚠".yellow());
        Ok(())
    } else {
        println!("{} {} of {} policy test(s) failed", "✗".red(), failed_tests, total_tests);
        Err(PolicyTestError::Other(anyhow::anyhow!("{} policy test(s) failed", failed_tests)))
    }
}

/// Check if conftest is available on PATH
fn check_conftest_available() -> Result<(), PolicyTestError> {
    let output = Command::new("conftest").arg("--version").output();

    match output {
        Ok(output) if output.status.success() => Ok(()),
        _ => Err(PolicyTestError::ConftestNotFound(
            "conftest not found on PATH\n\
            \n\
            Install conftest:\n\
              • macOS:     brew install conftest\n\
              • Linux:     See https://www.conftest.dev/install/\n\
              • Nix:       nix develop\n\
              • Container: docker run --rm openpolicyagent/conftest"
                .to_string(),
        )),
    }
}

/// Get workspace root directory
fn get_workspace_root() -> Result<PathBuf> {
    // From xtask directory, workspace root is ../../
    let current_dir = std::env::current_dir().context("Failed to get current directory")?;

    // Try to find Cargo.toml in workspace root
    let mut check_dir = current_dir.clone();
    for _ in 0..3 {
        let cargo_toml = check_dir.join("Cargo.toml");
        if cargo_toml.exists() {
            // Verify it's the workspace root by checking for policy directory
            if check_dir.join("policy").exists() {
                return Ok(check_dir);
            }
        }
        if let Some(parent) = check_dir.parent() {
            check_dir = parent.to_path_buf();
        } else {
            break;
        }
    }

    // Fallback: assume we're running from workspace root
    Ok(current_dir)
}

/// Find test fixtures for a policy area
fn find_test_fixtures(testdata_dir: &Path, area: &str) -> Result<Vec<(PathBuf, bool)>> {
    let mut fixtures = Vec::new();

    // Look for valid and invalid fixtures (both JSON and YAML)
    let valid_json = testdata_dir.join(format!("{}_valid.json", area));
    let valid_yaml = testdata_dir.join(format!("{}_valid.yaml", area));
    let invalid_json = testdata_dir.join(format!("{}_invalid.json", area));
    let invalid_yaml = testdata_dir.join(format!("{}_invalid.yaml", area));

    // Also check for alternative naming patterns - these all should fail validation
    let invalid_patterns = [
        "missing_tests",
        "no_tests",
        "missing_ac",
        "unknown_ac",
        "wrong_feature",
        "missing_include",
        "zero_bytes",
        "missing_required_task",
        "unknown_field",
        "missing_max_bytes",
        "runs_as_root",
        "no_labels",
        "literal_database_url",
        "literal_api_key",
        "configmap_for_secret",
    ];

    if valid_json.exists() {
        fixtures.push((valid_json, true));
    }

    if valid_yaml.exists() {
        fixtures.push((valid_yaml, true));
    }

    if invalid_json.exists() {
        fixtures.push((invalid_json, false));
    }

    if invalid_yaml.exists() {
        fixtures.push((invalid_yaml, false));
    }

    // Check for all invalid patterns (both JSON and YAML)
    for pattern in &invalid_patterns {
        let json_file = testdata_dir.join(format!("{}_{}.json", area, pattern));
        if json_file.exists() {
            fixtures.push((json_file, false));
        }

        let yaml_file = testdata_dir.join(format!("{}_{}.yaml", area, pattern));
        if yaml_file.exists() {
            fixtures.push((yaml_file, false));
        }
    }

    Ok(fixtures)
}

/// Run conftest test against a policy file and fixture
fn run_conftest_test(policy_file: &Path, fixture_file: &Path) -> Result<bool> {
    let output = Command::new("conftest")
        .arg("test")
        .arg("-p")
        .arg(policy_file)
        .arg(fixture_file)
        .output()
        .context("Failed to execute conftest")?;

    Ok(output.status.success())
}

use anyhow::{Context, Result};
use colored::Colorize;
use std::process::Command;

pub fn run() -> Result<()> {
    println!("{}", "Running pre-commit checks...".blue().bold());

    // 0. Auto-fix fmt first, then let check run on clean tree
    run_fmt_with_autostage()?;

    // 1. Core checks (fmt --check, clippy, tests)
    crate::commands::check::run()?;

    // Run Skills format and lint if relevant files changed
    run_skills_lint_if_changed()?;

    // Run Agents lint if relevant files changed
    run_agents_lint_if_changed()?;

    // Run AC status and auto-stage feature_status.md if it changed
    run_ac_status_with_autostage()?;

    // Run docs-check and spellcheck in soft mode (warnings only, unless XTASK_STRICT_PRECOMMIT=1)
    let strict = std::env::var("XTASK_STRICT_PRECOMMIT").unwrap_or_default() == "1";

    if std::env::var("XTASK_SKIP_DOCS_CHECK").unwrap_or_default() == "1" {
        println!("{} Skipping docs-check because XTASK_SKIP_DOCS_CHECK=1", "[WARN]".yellow());
    } else {
        match crate::commands::docs_check::run() {
            Ok(_) => {}
            Err(e) => {
                if strict {
                    println!("{} docs-check failed (strict mode enabled)", "[FAIL]".red());
                    return Err(e);
                } else {
                    println!("{} docs-check failed (continuing in soft mode)", "[WARN]".yellow());
                    println!("  {}", e.to_string().lines().next().unwrap_or(""));
                    println!("  💡 To fail on docs issues: XTASK_STRICT_PRECOMMIT=1");
                }
            }
        }
    }

    if std::env::var("XTASK_SKIP_SPELLCHECK").unwrap_or_default() == "1" {
        println!("{} Skipping spellcheck because XTASK_SKIP_SPELLCHECK=1", "[WARN]".yellow());
    } else {
        match crate::commands::spellcheck::run_with_default_targets() {
            Ok(_) => {}
            Err(e) => {
                if strict {
                    println!("{} spellcheck failed (strict mode enabled)", "[FAIL]".red());
                    return Err(e);
                } else {
                    println!("{} spellcheck failed (continuing in soft mode)", "[WARN]".yellow());
                    println!("  {}", e.to_string().lines().next().unwrap_or(""));
                    println!("  💡 To fail on spelling issues: XTASK_STRICT_PRECOMMIT=1");
                }
            }
        }
    }

    println!("{}", "Pre-commit checks completed".green().bold());
    Ok(())
}

fn stage_skill_docs_if_modified() -> Result<()> {
    let out = Command::new("git")
        .args(["diff", "--name-only", "--", ".claude/skills"])
        .output()
        .context("failed to run git diff for skills")?;

    let changed = String::from_utf8_lossy(&out.stdout);
    let files: Vec<&str> = changed.lines().map(str::trim).filter(|p| !p.is_empty()).collect();

    if files.is_empty() {
        return Ok(());
    }

    println!("{} Staging formatted Skills:", "✓".green());
    for f in &files {
        println!("  - {}", f);
        Command::new("git").args(["add", f]).status()?;
    }
    Ok(())
}

fn run_skills_lint_if_changed() -> Result<()> {
    // Check if any Skills-related files have changed (both staged and unstaged)
    let paths_to_check = [
        ".claude/skills/**",
        "docs/SKILLS_*.md",
        "specs/spec_ledger.yaml",
        "crates/xtask/src/commands/skills.rs",
    ];

    let mut has_changes = false;

    for pattern in &paths_to_check {
        // Check staged changes
        let staged_output = Command::new("git")
            .args(["diff", "--cached", "--name-only", "--", pattern])
            .output()?;

        let staged_str = String::from_utf8_lossy(&staged_output.stdout);
        if !staged_str.trim().is_empty() {
            has_changes = true;
            break;
        }

        // Check unstaged changes
        let unstaged_output =
            Command::new("git").args(["diff", "--name-only", "--", pattern]).output()?;

        let unstaged_str = String::from_utf8_lossy(&unstaged_output.stdout);
        if !unstaged_str.trim().is_empty() {
            has_changes = true;
            break;
        }
    }

    if !has_changes {
        println!("{} No Skills changes detected, skipping skills-lint", "⊘".cyan());
        return Ok(());
    }

    // Run Skills format first
    match crate::commands::skills::run_fmt() {
        Ok(_) => {}
        Err(_) => {
            // Skills fmt exits with code 1 if files were modified, which is expected
            println!("{} Skills format applied (files were modified)", "✓".green());
        }
    }

    // Auto-stage any formatted SKILL.md files
    stage_skill_docs_if_modified()?;

    // Then run lint (with errors causing failure)
    match crate::commands::skills::run_lint() {
        Ok(_) => {
            println!("{} Skills governance check passed", "✓".green());
        }
        Err(e) => {
            println!("{} Skills governance check failed: {}", "✗".red(), e);
            return Err(e);
        }
    }

    Ok(())
}

