use anyhow::{Context, Result};
use colored::Colorize;
use std::fs;

use super::versioning::{VersionInfo, VersionManifest, apply_changes, plan_changes};

pub fn run(version: &str, dry_run: bool) -> Result<()> {
    if dry_run {
        println!("{}", format!("📦 Preparing release {} (dry run)...", version).blue().bold());
    } else {
        println!("{}", format!("📦 Preparing release {}...", version).blue().bold());
    }
    println!();

    // Validate version format and create VersionInfo
    let version_info = VersionInfo::new(version).context("Invalid version format")?;

    // Load the version manifest
    let manifest = VersionManifest::load().context("Failed to load version manifest")?;

    // Plan changes from manifest
    let edits = plan_changes(&version_info, &manifest)?;

    // Apply version updates
    if !edits.is_empty() {
        apply_changes(&edits, dry_run)?;
    } else {
        println!("  No version changes needed (already up to date)");
    }

    // Handle CHANGELOG specially (insert skeleton, not replace)
    if !dry_run {
        if insert_changelog_skeleton(version, &version_info.date)? {
            println!("  {} CHANGELOG.md (skeleton inserted)", "✓".green());
        }
    } else {
        println!("\n{}", "CHANGELOG.md:".cyan());
        println!("  Would insert new release section for [{}]", version);
    }

    // Summary
    println!();
    if dry_run {
        println!("{}", "This was a dry run. No files were modified.".yellow().bold());
        println!("Run without --dry-run to apply changes.");
    } else {
        let version_full = format!("v{}", version);
        println!("{}", "Next steps:".bold());
        println!("  1. Fill in {} entry", "CHANGELOG.md".cyan());
        println!("  2. Review all changes: {}", "git diff".cyan());
        println!("  3. Run: {}", "cargo xtask docs-check".cyan());
        println!("  4. Run: {}", "cargo xtask selftest".cyan());
        println!("  5. Commit: {}", format!("git commit -am 'Release {}'", version_full).cyan());
        println!(
            "  6. Tag: {}",
            format!("git tag -a {} -m 'Release {}'", version_full, version).cyan()
        );
    }

    Ok(())
}

fn insert_changelog_skeleton(version: &str, date: &str) -> Result<bool> {
    let path = "CHANGELOG.md";
    let content = fs::read_to_string(path)?;

    // Find [Unreleased] and insert new version after it
    let skeleton = format!(
        r#"
## [{}] - {}

### Added

- 

### Changed

- 

### Fixed

- 
"#,
        version, date
    );

    let new_content =
        content.replace("## [Unreleased]", &format!("## [Unreleased]\n\n(empty)\n{}", skeleton));

    fs::write(path, new_content)?;
    Ok(true)
}

use anyhow::Result;
use colored::Colorize;
use std::env;

pub fn run() -> Result<()> {
    println!("{}", "🚀 Running release verification...".blue().bold());
    println!();

    let mut failed = Vec::new();

    // Run selftest without re-entering the BDD harness
    println!("{}", "[1/3] Running selftest...".bold());
    let prev_skip_bdd = env::var("XTASK_SKIP_BDD").ok();
    // SAFETY: Nested selftest runs within BDD need to skip BDD recursion.
    unsafe {
        env::set_var("XTASK_SKIP_BDD", "1");
    }
    let selftest_result = crate::commands::selftest::run_with_verbosity(crate::Verbosity::Normal);
    unsafe {
        if let Some(prev) = prev_skip_bdd {
            env::set_var("XTASK_SKIP_BDD", prev);
        } else {
            env::remove_var("XTASK_SKIP_BDD");
        }
    }

    match selftest_result {
        Ok(_) => println!("{} Selftest passed\n", "✓".green()),
        Err(e) => {
            println!("{} Selftest failed\n", "✗".red());
            eprintln!("{}", e);
            failed.push("selftest");
        }
    }

    // Run audit
    println!("{}", "[2/3] Running audit...".bold());
    match crate::commands::audit::run() {
        Ok(_) => println!("{} Audit passed\n", "✓".green()),
        Err(e) => {
            println!("{} Audit failed\n", "✗".red());
            eprintln!("{}", e);
            failed.push("audit");
        }
    }

    // Run docs-check
    println!("{}", "[3/3] Running docs-check...".bold());
    match crate::commands::docs_check::run() {
        Ok(_) => println!("{} Docs-check passed\n", "✓".green()),
        Err(e) => {
            println!("{} Docs-check failed\n", "✗".red());
            eprintln!("{}", e);
            failed.push("docs-check");
        }
    }

    // Check working tree
    let skip_git_status = env::var("XTASK_SKIP_GIT_STATUS").is_ok()
        || env::var("XTASK_LOW_RESOURCES").unwrap_or_default() == "1";
    if skip_git_status {
        println!("{} Skipping git status check (low-resource/test mode)\n", "?".yellow());
    } else {
        println!("{}", "Checking working tree...".bold());
        let output = std::process::Command::new("git").args(["status", "--porcelain"]).output()?;

        let status = String::from_utf8_lossy(&output.stdout);
        if !status.trim().is_empty() {
            println!("{} Working tree is dirty", "✗".red());
            println!("{}", status);
            failed.push("git-clean");
        } else {
            println!("{} Working tree clean\n", "✓".green());
        }
    }

    // Summary
    println!("{}", "=".repeat(40));
    if failed.is_empty() {
        println!("{}", "✓ Release verification passed!".green().bold());
        println!();
        println!("{}", "Git command sequence:".bold());
        println!("  {}", "git commit -am 'Release vX.Y.Z'".cyan());
        println!("  {}", "git tag -a vX.Y.Z -m 'Release vX.Y.Z'".cyan());
        println!("  {}", "git push origin main --follow-tags".cyan());
    } else {
        println!("{}", "✗ Release verification failed".red().bold());
        println!();
        println!("Failed checks:");
        for check in &failed {
            println!("  • {}", check);
        }
        println!();
        println!("{}", "Fix issues above and re-run:".bold());
        println!("  {}", "cargo xtask release-verify".cyan());
        anyhow::bail!("{} check(s) failed", failed.len());
    }

    Ok(())
}

use anyhow::Result;
use colored::Colorize;
use std::fs;
use std::path::Path;
use std::process::Command;

pub fn run() -> Result<()> {
    println!("{}", "📋 Generating local SBOM...".blue().bold());
    println!();

    // Create target directory if it doesn't exist
    fs::create_dir_all("target")?;

    // Generate SBOM using cargo tree
    print!("Generating SBOM from dependency tree... ");

    let output = Command::new("cargo").args(["tree", "--format", "{p} {l}"]).output()?;

    if !output.status.success() {
        println!("{}", "✗ Failed".red());
        anyhow::bail!("cargo tree command failed");
    }

    // Create a simple SPDX-like JSON structure
    let tree_output = String::from_utf8_lossy(&output.stdout);

    let sbom = serde_json::json!({
        "spdxVersion": "SPDX-2.3",
        "dataLicense": "CC0-1.0",
        "SPDXID": "SPDXRef-DOCUMENT",
        "name": "Rust-Template-SBOM",
        "documentNamespace": format!("https://github.com/EffortlessMetrics/Rust-Template/sbom-{}",
            chrono::Local::now().format("%Y%m%d%H%M%S")),
        "creationInfo": {
            "created": chrono::Local::now().to_rfc3339(),
            "creators": ["Tool: cargo-tree via xtask"]
        },
        "packages": tree_output.lines()
            .filter_map(|line| {
                let parts: Vec<&str> = line.split_whitespace().collect();
                if parts.len() >= 2 {
                    Some(serde_json::json!({
                        "name": parts[0],
                        "SPDXID": format!("SPDXRef-{}", parts[0].replace(['/', '-', '.'], "_")),
                        "versionInfo": parts.get(1).unwrap_or(&"unknown"),
                        "licenseConcluded": parts.get(2).unwrap_or(&"NOASSERTION")
                    }))
                } else {
                    None
                }
            })
            .collect::<Vec<_>>()
    });

    // Write SBOM
    let sbom_path = Path::new("target/sbom.spdx.json");
    fs::write(sbom_path, serde_json::to_string_pretty(&sbom)?)?;

    println!("{}", "✓ Done".green());
    println!();
    println!("{} SBOM written to: {}", "📄".cyan(), sbom_path.display());
    println!();
    println!("{}", "Note:".bold());
    println!("  This is a simplified local SBOM for development.");
    println!("  For CI-grade attestations & provenance, see:");
    println!("  {}", "docs/explanation/supply-chain-hardening.md".cyan());
    println!();
    println!("  CI generates official SBOMs on tagged releases via:");
    println!("  {}", ".github/workflows/ci-supply-chain.yml".dimmed());

    Ok(())
}

