/// Display governance status dashboard
pub fn run() -> Result<()> {
    let ledger_path = Path::new("specs/spec_ledger.yaml");
    let tasks_path = Path::new("specs/tasks.yaml");
    let feature_status_path = Path::new("docs/feature_status.md");

    // Parse ledger
    let ledger = parse_ledger(ledger_path)?;
    let (story_count, req_count, ac_count) = count_governance(&ledger);

    // Parse tasks
    let task_counts = parse_tasks(tasks_path)?;

    // Parse AC coverage
    let ac_coverage = parse_ac_coverage(feature_status_path);

    // Load questions
    let questions = questions::load_all_questions().unwrap_or_default();
    let question_stats = questions::calculate_stats(&questions);

    // Load friction
    let friction_entries = friction::load_all_friction_entries().unwrap_or_default();
    let friction_stats = friction::calculate_stats(&friction_entries);

    // Display status
    print_status_dashboard(
        &ledger.metadata.template_version,
        story_count,
        req_count,
        ac_count,
        &task_counts,
        &ac_coverage,
        &question_stats,
        &questions,
        &friction_stats,
        &friction_entries,
    );

    Ok(())
}

fn parse_ledger(ledger_path: &Path) -> Result<Ledger> {
    let content = fs::read_to_string(ledger_path)
        .with_context(|| format!("Failed to read ledger: {}", ledger_path.display()))?;

    let ledger: Ledger = serde_yaml::from_str(&content)
        .with_context(|| format!("Failed to parse ledger YAML: {}", ledger_path.display()))?;

    Ok(ledger)
}

fn count_governance(ledger: &Ledger) -> (usize, usize, usize) {
    let story_count = ledger.stories.len();
    let req_count: usize = ledger.stories.iter().map(|s| s.requirements.len()).sum();
    let ac_count: usize = ledger
        .stories
        .iter()
        .flat_map(|s| &s.requirements)
        .map(|r| r.acceptance_criteria.len())
        .sum();

    (story_count, req_count, ac_count)
}

fn parse_tasks(tasks_path: &Path) -> Result<HashMap<String, usize>> {
    if !tasks_path.exists() {
        // Tasks file is optional
        return Ok(HashMap::new());
    }

    let content = fs::read_to_string(tasks_path)
        .with_context(|| format!("Failed to read tasks: {}", tasks_path.display()))?;

    let tasks_file: TasksFile = serde_yaml::from_str(&content)
        .with_context(|| format!("Failed to parse tasks YAML: {}", tasks_path.display()))?;

    let mut counts: HashMap<String, usize> = HashMap::new();
    for task in tasks_file.tasks {
        let status = task.status.unwrap_or_else(|| "open".to_string());
        *counts.entry(status).or_insert(0) += 1;
    }

    Ok(counts)
}

fn parse_ac_coverage(feature_status_path: &Path) -> Option<AcCoverage> {
    // If the file doesn't exist, AC coverage is not available
    if !feature_status_path.exists() {
        return None;
    }

    let content = match fs::read_to_string(feature_status_path) {
        Ok(c) => c,
        Err(_) => return None,
    };

    let mut coverage = AcCoverage::default();

    for line in content.lines() {
        if let Some(caps) = AC_STATUS_PATTERN.captures(line) {
            // Extract status text (pass/fail/unknown)
            let status = caps.get(2).map(|m| m.as_str()).unwrap_or("");
            match status {
                "pass" => coverage.pass += 1,
                "fail" => coverage.fail += 1,
                "unknown" => coverage.unknown += 1,
                _ => {}
            }
        }
    }

    // Only return coverage if we found at least one AC
    if coverage.total() > 0 { Some(coverage) } else { None }
}

#[allow(clippy::too_many_arguments)]
fn print_status_dashboard(
    version: &str,
    story_count: usize,
    req_count: usize,
    ac_count: usize,
    task_counts: &HashMap<String, usize>,
    ac_coverage: &Option<AcCoverage>,
    question_stats: &questions::QuestionStats,
    all_questions: &[questions::Question],
    friction_stats: &friction::FrictionStats,
    all_friction: &[friction::FrictionEntry],
) {
    println!();
    println!("{}", "======================================".blue());
    println!("{}", format!("Rust-as-Spec – {}", version).bold());
    println!("{}", "======================================".blue());
    println!();

    // Governance metrics
    println!("{}", "Governance:".bold());
    println!("  Stories:      {}", story_count);
    println!("  Requirements: {}", req_count);
    println!("  ACs:          {}", ac_count);

    // AC Coverage metrics (integrated into Governance section)
    if let Some(coverage) = ac_coverage {
        // Build the coverage line with color based on failures
        let coverage_line = if coverage.fail > 0 {
            format!(
                "  AC coverage:  {} pass, {} fail, {} unknown (BDD)",
                coverage.pass, coverage.fail, coverage.unknown
            )
            .yellow()
            .to_string()
        } else if coverage.unknown == 0 && coverage.pass > 0 {
            format!(
                "  AC coverage:  {} pass, {} fail, {} unknown (BDD)",
                coverage.pass, coverage.fail, coverage.unknown
            )
            .green()
            .to_string()
        } else {
            format!(
                "  AC coverage:  {} pass, {} fail, {} unknown (BDD)",
                coverage.pass, coverage.fail, coverage.unknown
            )
        };

        println!("{}", coverage_line);
        println!("  See: {}", "docs/feature_status.md".blue());
    } else {
        // No AC coverage data available yet
        println!("  AC coverage:  N/A (run acceptance tests)");
    }
    println!();

    // Task metrics
    if !task_counts.is_empty() {
        println!("{}", "Tasks:".bold());
        for (status, count) in task_counts.iter() {
            let status_display = match status.as_str() {
                "open" => format!("Todo:        {}", count),
                "in_progress" => format!("InProgress:  {}", count).yellow().to_string(),
                "review" => format!("Review:      {}", count).cyan().to_string(),
                "done" => format!("Done:        {}", count).green().to_string(),
                _ => format!("{:12} {}", status, count),
            };
            println!("  {}", status_display);
        }
        println!();
    }

    // Question metrics
    if question_stats.total_count > 0 {
        println!("{}", "Questions:".bold());
        let open_display = if question_stats.open_count > 0 {
            format!("  Open:        {}", question_stats.open_count).yellow().to_string()
        } else {
            format!("  Open:        {}", question_stats.open_count)
        };
        println!("{}", open_display);
        println!("  Answered:    {}", question_stats.answered_count);
        println!("  Resolved:    {}", question_stats.resolved_count);
        println!("  Total:       {}", question_stats.total_count);

        // Show top 1-3 open questions
        let open_questions: Vec<&questions::Question> =
            all_questions.iter().filter(|q| q.status == "open").take(3).collect();

        if !open_questions.is_empty() {
            println!();
            for q in open_questions {
                println!("  {} {}", "⚠️".yellow(), q.id);
                println!("    {}", q.summary.dimmed());
            }
        }

        println!("  See: {}", "questions/ directory".blue());
        println!();
    }

    // Friction metrics
    if friction_stats.total_count > 0 {
        println!("{}", "Friction:".bold());
        let open_display = if friction_stats.open_count > 0 {
            format!("  Open:        {}", friction_stats.open_count).yellow().to_string()
        } else {
            format!("  Open:        {}", friction_stats.open_count)
        };
        println!("{}", open_display);
        println!("  Resolved:    {}", friction_stats.resolved_count);
        println!("  Total:       {}", friction_stats.total_count);

        // Show severity breakdown
        let has_critical = friction_stats.by_severity.critical > 0;
        let has_high = friction_stats.by_severity.high > 0;
        if has_critical || has_high {
            println!();
            if has_critical {
                println!(
                    "  {} Critical: {}",
                    "🔥".red(),
                    friction_stats.by_severity.critical.to_string().red()
                );
            }
            if has_high {
                println!(
                    "  {} High:     {}",
                    "❗".yellow(),
                    friction_stats.by_severity.high.to_string().yellow()
                );
            }
        }

        // Show top 1-3 open friction entries
        let open_friction: Vec<&friction::FrictionEntry> =
            all_friction.iter().filter(|f| f.status == "open").take(3).collect();

        if !open_friction.is_empty() {
            println!();
            for f in open_friction {
                let severity_icon = match f.severity.as_str() {
                    "critical" => "🔥",
                    "high" => "❗",
                    "medium" => "⚠️",
                    "low" => "ℹ️",
                    _ => "•",
                };
                println!("  {} {}", severity_icon.yellow(), f.id);
                println!("    {}", f.summary.dimmed());
            }
        }

        println!("  See: {}", "FRICTION_LOG.md and friction/ directory".blue());
        println!();
    }

    // Suggested next steps
    println!("{}", "Next steps:".bold());
    println!("  • View tasks:     {}", "cargo xtask tasks-list".blue());
    println!("  • Run selftest:   {}", "cargo xtask selftest".blue());
    println!("  • Start platform: {}", "cargo run -p app-http".blue());
    println!("  • View UI:        {}", "http://localhost:8080/ui".blue());
    println!("{}", "======================================".blue());
    println!();
}

use anyhow::Result;
use clap::Parser;
use colored::Colorize;
use serde::Serialize;
use spec_runtime::hints::{self, HintEngine};

use super::tasks::spec_root;

#[derive(Debug, Parser)]
pub struct SuggestNextArgs {
    /// Filter by owner name
    #[arg(long)]
    pub owner: Option<String>,

    /// Filter by label/tag
    #[arg(long)]
    pub label: Option<String>,

    /// Filter by requirement ID
    #[arg(long)]
    pub requirement: Option<String>,

    /// Maximum number of hints to return
    #[arg(long)]
    pub limit: Option<usize>,

    /// Output format (table or json)
    #[arg(long, default_value = "table")]
    pub format: String,
}

#[derive(Debug, Serialize)]
pub struct CliHint {
    pub task_id: String,
    pub title: String,
    pub status: String,
    pub owner: String,
    pub labels: Vec<String>,
    pub requirement_ids: Vec<String>,
    pub ac_ids: Vec<String>,
    pub reason: String,
}

#[derive(Debug, Serialize)]
pub struct CliHintsResponse {
    pub hints: Vec<CliHint>,
}

pub fn run(args: SuggestNextArgs) -> Result<()> {
    let root = spec_root();

    // Load tasks and AC coverage
    let tasks_path = root.join("specs/tasks.yaml");
    let task_specs = spec_runtime::load_tasks(&tasks_path)?;

    let feature_status_path = root.join("docs/feature_status.md");
    let ac_index = hints::parse_feature_status(&feature_status_path)?;

    // Convert task specs to runtime tasks
    let runtime_tasks: Vec<spec_runtime::Task> = task_specs
        .tasks
        .iter()
        .map(|t| spec_runtime::Task {
            id: t.id.clone(),
            title: t.title.clone(),
            status: t.status.clone(),
            requirement: t.requirement.clone(),
            acs: t.acs.clone(),
            labels: t.labels.clone(),
            owner: t.owner.clone(),
            docs: None,
            summary: t.summary.clone(),
            recommended_flows: t.recommended_flows.clone(),
            depends_on: vec![],
        })
        .collect();

    // Create HintEngine
    let engine = HintEngine::new(ac_index, runtime_tasks.clone());
    let hint_engine_hints = engine.task_hints();

    // Convert to CLI hints and apply filters
    let mut cli_hints: Vec<CliHint> = hint_engine_hints
        .iter()
        .filter_map(|hint| {
            // Only include Todo and InProgress hints (HintEngine filters these)
            if !matches!(hint.status, hints::HintStatus::Open | hints::HintStatus::InProgress) {
                return None;
            }

            let task_id = match &hint.target {
                hints::HintTarget::Task { id } => id.clone(),
                _ => return None,
            };

            // Find the original task definition for metadata
            let task_def = runtime_tasks.iter().find(|t| t.id == task_id)?;

            // Apply owner filter
            if let Some(ref owner_filter) = args.owner {
                let hint_owner = task_def.owner.as_deref().unwrap_or("unassigned");
                if !hint_owner.eq_ignore_ascii_case(owner_filter) {
                    return None;
                }
            }

            // Apply label filter
            if let Some(ref label_filter) = args.label
                && !hint.tags.iter().any(|l| l.eq_ignore_ascii_case(label_filter))
            {
                return None;
            }

            // Apply requirement filter
            if let Some(ref req_filter) = args.requirement
                && !task_def.requirement.eq_ignore_ascii_case(req_filter)
            {
                return None;
            }

            Some(CliHint {
                task_id,
                title: hint.title.clone(),
                status: match hint.status {
                    hints::HintStatus::Open => "open".to_string(),
                    hints::HintStatus::InProgress => "in_progress".to_string(),
                    hints::HintStatus::Done => "done".to_string(),
                },
                owner: task_def.owner.clone().unwrap_or_else(|| "unassigned".to_string()),
                labels: hint.tags.clone(),
                requirement_ids: vec![task_def.requirement.clone()],
                ac_ids: task_def.acs.clone(),
                reason: hint.reason.details.clone(),
            })
        })
        .collect();

    // Sort by status (in_progress before open) then by ID
    cli_hints.sort_by(|a, b| {
        let status_order_a = if a.status == "in_progress" { 0 } else { 1 };
        let status_order_b = if b.status == "in_progress" { 0 } else { 1 };

        match status_order_a.cmp(&status_order_b) {
            std::cmp::Ordering::Equal => a.task_id.cmp(&b.task_id),
            other => other,
        }
    });

    // Apply limit
    if let Some(limit) = args.limit {
        cli_hints.truncate(limit);
    }

    // Output based on format
    if args.format == "json" {
        let response = CliHintsResponse { hints: cli_hints };
        println!("{}", serde_json::to_string_pretty(&response)?);
    } else {
        println!("{}", "Agent Hints".bold());
        println!();

        if cli_hints.is_empty() {
            println!("No hints match the current filters.");
            return Ok(());
        }

        for (idx, hint) in cli_hints.iter().enumerate() {
            let status_badge = if hint.status == "in_progress" {
                "[IN PROGRESS]".yellow()
            } else {
                "[OPEN]".cyan()
            };

            println!("{} {} ({})", idx + 1, status_badge, hint.task_id.bold());
            println!("  Title: {}", hint.title);
            println!("  Owner: {}", hint.owner);
            if !hint.labels.is_empty() {
                println!("  Labels: {}", hint.labels.join(", ").dimmed());
            }
            println!("  Reason: {}", hint.reason);
            println!("  ACs: {}", hint.ac_ids.join(", ").dimmed());
            println!();
        }
    }

    Ok(())
}

use anyhow::{Context, Result, bail};
use business_core::governance::TaskStatus;
use spec_runtime::{
    ledger::SpecLedger,
    load_spec_ledger, load_tasks,
    tasks::{Task, TaskDocs, TasksSpec},
};
use std::collections::HashSet;
use std::fs;
use std::path::{Path, PathBuf};

pub fn spec_root() -> PathBuf {
    if let Ok(root) = std::env::var("SPEC_ROOT") {
        return PathBuf::from(root);
    }

    PathBuf::from(env!("CARGO_MANIFEST_DIR")).parent().unwrap().parent().unwrap().to_path_buf()
}

pub fn create_task(
    id: &str,
    title: &str,
    requirement: &str,
    acs: &[String],
    owner: Option<String>,
    status: Option<String>,
    labels: &[String],
) -> Result<()> {
    let root = spec_root();
    let ledger = load_spec_ledger(&root.join("specs/spec_ledger.yaml"))?;

    validate_requirement_and_acs(&ledger, requirement, acs)?;

    let tasks_path = root.join("specs/tasks.yaml");
    let mut tasks_spec = load_tasks(&tasks_path)?;

    if tasks_spec.tasks.iter().any(|t| t.id == id) {
        bail!("Task {} already exists in {}", id, tasks_path.display());
    }

    let desired_status =
        status.as_deref().map(parse_status).transpose()?.unwrap_or(TaskStatus::Todo);

    let new_task = Task {
        id: id.to_string(),
        title: title.to_string(),
        requirement: requirement.to_string(),
        acs: acs.to_vec(),
        status: format_status(&desired_status),
        owner,
        labels: labels.to_vec(),
        docs: Some(TaskDocs { design: Vec::new(), plan: Vec::new() }),
        summary: title.to_string(),
        recommended_flows: Vec::new(),
        depends_on: Vec::new(),
    };

    tasks_spec.tasks.push(new_task);
    write_tasks(&tasks_path, &tasks_spec)?;

    println!(
        "Created task {} (requirement: {}, status: {})",
        id,
        requirement,
        format_status(&desired_status)
    );

    Ok(())
}

pub fn update_task(
    id: &str,
    title: Option<String>,
    owner: Option<String>,
    status: Option<String>,
) -> Result<()> {
    let root = spec_root();
    let tasks_path = root.join("specs/tasks.yaml");
    let mut tasks_spec = load_tasks(&tasks_path)?;

    let task = tasks_spec.tasks.iter_mut().find(|t| t.id == id).context(format!(
        "Task {} not found in {}",
        id,
        tasks_path.display()
    ))?;

    let current_status = parse_status(&task.status)?;

    if let Some(new_title) = title {
        task.title = new_title.clone();
        task.summary = new_title;
    }

    if let Some(new_owner) = owner {
        task.owner = Some(new_owner);
    }

    if let Some(status_text) = status {
        let new_status = parse_status(&status_text)?;
        if current_status != new_status && !current_status.can_transition_to(&new_status) {
            bail!(
                "Invalid status transition for {}: {} -> {}",
                id,
                format_status(&current_status),
                format_status(&new_status)
            );
        }
        task.status = format_status(&new_status);
    }

    write_tasks(&tasks_path, &tasks_spec)?;

    println!("Updated task {}", id);
    Ok(())
}

fn write_tasks(path: &Path, tasks: &TasksSpec) -> Result<()> {
    if let Some(parent) = path.parent() {
        fs::create_dir_all(parent)?;
    }
    let yaml = serde_yaml::to_string(tasks)?;
    fs::write(path, yaml)?;
    Ok(())
}

fn parse_status(raw: &str) -> Result<TaskStatus> {
    match raw.trim().to_lowercase().as_str() {
        "todo" | "open" => Ok(TaskStatus::Todo),
        "inprogress" | "in_progress" | "in-progress" | "in progress" => Ok(TaskStatus::InProgress),
        "review" => Ok(TaskStatus::Review),
        "done" | "completed" => Ok(TaskStatus::Done),
        other => bail!("Invalid status '{}'. Use one of: Todo, InProgress, Review, Done.", other),
    }
}

fn format_status(status: &TaskStatus) -> String {
    match status {
        TaskStatus::Todo => "Todo",
        TaskStatus::InProgress => "InProgress",
        TaskStatus::Review => "Review",
        TaskStatus::Done => "Done",
    }
    .to_string()
}

fn validate_requirement_and_acs(
    ledger: &SpecLedger,
    requirement: &str,
    acs: &[String],
) -> Result<()> {
    let mut req_found = false;
    let mut ac_set: HashSet<&str> = HashSet::new();

    for story in &ledger.stories {
        for req in &story.requirements {
            if req.id == requirement {
                req_found = true;
                for ac in &req.acceptance_criteria {
                    ac_set.insert(ac.id.as_str());
                }
            }
        }
    }

    if !req_found {
        bail!("Requirement {} not found in spec_ledger.yaml", requirement);
    }

    for ac in acs {
        if !ac_set.contains(ac.as_str()) {
            bail!("Acceptance criterion {} not found under requirement {}", ac, requirement);
        }
    }

    Ok(())
}

#[cfg(test)]
mod tests {
    use super::*;

    /// AC-TPL-XTASK-SPEC-ROOT: Verifies that spec_root() resolves via SPEC_ROOT
    /// environment variable when set, enabling BDD tests to operate on temporary workspaces.
    #[test]
    fn spec_root_resolved() {
        // Save original value if set
        let original = std::env::var("SPEC_ROOT").ok();
        let had_original = original.is_some();

        // Test with SPEC_ROOT set
        let test_path = "/tmp/test-spec-root";
        // SAFETY: This test runs in isolation and we restore the env var after
        unsafe { std::env::set_var("SPEC_ROOT", test_path) };
        let resolved = spec_root();
        assert_eq!(
            resolved,
            PathBuf::from(test_path),
            "spec_root should return SPEC_ROOT value when set"
        );

        // Restore original value
        // SAFETY: Restoring the original environment state
        if let Some(orig) = original {
            unsafe { std::env::set_var("SPEC_ROOT", orig) };
        } else {
            unsafe { std::env::remove_var("SPEC_ROOT") };
        }

        // Test without SPEC_ROOT (should fall back to repo root via CARGO_MANIFEST_DIR)
        // Skip this check if original was set (we just restored it)
        if !had_original {
            let fallback = spec_root();
            assert!(
                fallback.exists(),
                "spec_root should return a valid path when SPEC_ROOT is unset"
            );
        }
    }
}

