    #[test]
    fn test_apply_changes_actual() {
        use std::io::Write;
        use tempfile::TempDir;

        // Create a temp directory with test files
        let temp_dir = TempDir::new().expect("Failed to create temp dir");
        let temp_path = temp_dir.path();

        // Create a test file
